package com.eflglobal.visitorsapp

import android.content.pm.ActivityInfo
import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.activity.viewModels
import androidx.core.splashscreen.SplashScreen.Companion.installSplashScreen
import com.eflglobal.visitorsapp.ui.VisitorsAppRoot
import com.eflglobal.visitorsapp.ui.viewmodel.SplashViewModel

class MainActivity : ComponentActivity() {

    private val splashViewModel: SplashViewModel by viewModels {
        SplashViewModel.Factory(applicationContext)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        val splash = installSplashScreen()

        // Keep the splash visible until BOTH:
        //  1. The station check has resolved (not Loading)
        //  2. At least 2 seconds have elapsed
        val startTime = System.currentTimeMillis()
        splash.setKeepOnScreenCondition {
            val elapsed = System.currentTimeMillis() - startTime
            splashViewModel.isLoading || elapsed < 2_000L
        }

        super.onCreate(savedInstanceState)

        requestedOrientation = ActivityInfo.SCREEN_ORIENTATION_LANDSCAPE

        enableEdgeToEdge()
        setContent {
            VisitorsAppRoot(splashViewModel = splashViewModel)
        }
    }
}

package com.eflglobal.visitorsapp

import android.content.pm.ActivityInfo
import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.activity.viewModels
import androidx.core.splashscreen.SplashScreen.Companion.installSplashScreen
import androidx.core.view.WindowCompat
import androidx.core.view.WindowInsetsCompat
import androidx.core.view.WindowInsetsControllerCompat
import com.eflglobal.visitorsapp.ui.VisitorsAppRoot
import com.eflglobal.visitorsapp.ui.viewmodel.SplashViewModel

class MainActivity : ComponentActivity() {

    private val splashViewModel: SplashViewModel by viewModels {
        SplashViewModel.Factory(applicationContext)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        val splash = installSplashScreen()

        // Keep the splash visible until BOTH:
        //  1. The station check has resolved (not Loading)
        //  2. At least 2 seconds have elapsed
        val startTime = System.currentTimeMillis()
        splash.setKeepOnScreenCondition {
            val elapsed = System.currentTimeMillis() - startTime
            splashViewModel.isLoading || elapsed < 2_000L
        }

        super.onCreate(savedInstanceState)

        requestedOrientation = ActivityInfo.SCREEN_ORIENTATION_LANDSCAPE

        // Edge-to-edge + fullscreen: content draws behind system bars, then bars are hidden
        enableEdgeToEdge()
        WindowCompat.setDecorFitsSystemWindows(window, false)
        hideSystemBars()

        setContent {
            VisitorsAppRoot(splashViewModel = splashViewModel)
        }
    }

    override fun onWindowFocusChanged(hasFocus: Boolean) {
        super.onWindowFocusChanged(hasFocus)
        // Re-hide bars when app regains focus (e.g. after a notification shade)
        if (hasFocus) hideSystemBars()
    }

    private fun hideSystemBars() {
        val controller = WindowInsetsControllerCompat(window, window.decorView)
        // Hide both status bar and navigation bar
        controller.hide(WindowInsetsCompat.Type.systemBars())
        // Allow user to temporarily reveal bars by swiping from edge
        controller.systemBarsBehavior =
            WindowInsetsControllerCompat.BEHAVIOR_SHOW_TRANSIENT_BARS_BY_SWIPE
    }
}

package com.eflglobal.visitorsapp.core.utils

import android.content.Context
import android.graphics.Bitmap
import java.io.File
import java.io.FileOutputStream

/**
 * Utilidad para guardar imágenes en el almacenamiento interno.
 *
 * Organiza las imágenes por persona en carpetas:
 * /storage/internal/visitors/{personId}/
 *   - document_front.jpg
 *   - document_back.jpg
 *   - profile.jpg
 */
object ImageSaver {

    /**
     * Tipo de imagen del visitante.
     */
    enum class ImageType(val filename: String) {
        DOCUMENT_FRONT("document_front.jpg"),
        DOCUMENT_BACK("document_back.jpg"),
        PROFILE("profile.jpg"),
        QR_CODE("qr_code.png")
    }

    /**
     * Guarda una imagen en el almacenamiento interno.
     *
     * @param context Contexto de la aplicación
     * @param bitmap Imagen a guardar
     * @param personId ID de la persona (UUID)
     * @param imageType Tipo de imagen
     * @return Path completo del archivo guardado
     */
    fun saveImage(
        context: Context,
        bitmap: Bitmap,
        personId: String,
        imageType: ImageType
    ): String {
        // Crear directorio para la persona si no existe
        val personDir = File(context.filesDir, "visitors/$personId")
        if (!personDir.exists()) {
            personDir.mkdirs()
        }

        // Crear archivo
        val imageFile = File(personDir, imageType.filename)

        // Guardar bitmap
        FileOutputStream(imageFile).use { outputStream ->
            val format = if (imageType == ImageType.QR_CODE) {
                Bitmap.CompressFormat.PNG
            } else {
                Bitmap.CompressFormat.JPEG
            }
            val quality = if (imageType == ImageType.QR_CODE) 100 else 90

            bitmap.compress(format, quality, outputStream)
            outputStream.flush()
        }

        return imageFile.absolutePath
    }

    /**
     * Guarda una imagen para una visita (como QR).
     *
     * @param context Contexto de la aplicación
     * @param bitmap Imagen a guardar
     * @param visitId ID de la visita
     * @return Path completo del archivo guardado
     */
    fun saveVisitImage(
        context: Context,
        bitmap: Bitmap,
        visitId: String
    ): String {
        // Crear directorio para visitas si no existe
        val visitsDir = File(context.filesDir, "visits")
        if (!visitsDir.exists()) {
            visitsDir.mkdirs()
        }

        // Crear archivo
        val imageFile = File(visitsDir, "$visitId.png")

        // Guardar bitmap
        FileOutputStream(imageFile).use { outputStream ->
            bitmap.compress(Bitmap.CompressFormat.PNG, 100, outputStream)
            outputStream.flush()
        }

        return imageFile.absolutePath
    }

    /**
     * Obtiene el path de una imagen guardada.
     *
     * @param context Contexto de la aplicación
     * @param personId ID de la persona
     * @param imageType Tipo de imagen
     * @return Path del archivo o null si no existe
     */
    fun getImagePath(
        context: Context,
        personId: String,
        imageType: ImageType
    ): String? {
        val imageFile = File(context.filesDir, "visitors/$personId/${imageType.filename}")
        return if (imageFile.exists()) {
            imageFile.absolutePath
        } else {
            null
        }
    }

    /**
     * Elimina todas las imágenes de una persona.
     *
     * @param context Contexto de la aplicación
     * @param personId ID de la persona
     * @return true si se eliminaron correctamente
     */
    fun deletePersonImages(
        context: Context,
        personId: String
    ): Boolean {
        val personDir = File(context.filesDir, "visitors/$personId")
        return if (personDir.exists()) {
            personDir.deleteRecursively()
        } else {
            false
        }
    }

    /**
     * Obtiene el tamaño total de almacenamiento usado por las imágenes.
     *
     * @param context Contexto de la aplicación
     * @return Tamaño en bytes
     */
    fun getTotalStorageSize(context: Context): Long {
        val visitorsDir = File(context.filesDir, "visitors")
        val visitsDir = File(context.filesDir, "visits")

        var totalSize = 0L

        if (visitorsDir.exists()) {
            totalSize += visitorsDir.walkTopDown().filter { it.isFile }.map { it.length() }.sum()
        }

        if (visitsDir.exists()) {
            totalSize += visitsDir.walkTopDown().filter { it.isFile }.map { it.length() }.sum()
        }

        return totalSize
    }
}

package com.eflglobal.visitorsapp.core.utils

import android.content.Context
import android.graphics.Bitmap
import java.io.File
import java.io.FileOutputStream

/**
 * Utilidad para guardar imágenes en el almacenamiento interno.
 *
 * Organiza las imágenes por persona en carpetas:
 * /storage/internal/visitors/{personId}/
 *   - document_front.jpg
 *   - document_back.jpg
 *   - profile.jpg
 */
object ImageSaver {

    /**
     * Tipo de imagen del visitante.
     */
    enum class ImageType(val filename: String) {
        DOCUMENT_FRONT("document_front.jpg"),
        DOCUMENT_BACK("document_back.jpg"),
        PROFILE("profile.jpg"),
        QR_CODE("qr_code.png")
    }

    /**
     * Guarda una imagen en el almacenamiento interno.
     *
     * @param context Contexto de la aplicación
     * @param bitmap Imagen a guardar
     * @param personId ID de la persona (UUID)
     * @param imageType Tipo de imagen
     * @return Path completo del archivo guardado
     */
    fun saveImage(
        context: Context,
        bitmap: Bitmap,
        personId: String,
        imageType: ImageType
    ): String {
        // Crear directorio para la persona si no existe
        val personDir = File(context.filesDir, "visitors/$personId")
        if (!personDir.exists()) {
            personDir.mkdirs()
        }

        // Crear archivo
        val imageFile = File(personDir, imageType.filename)

        // Guardar bitmap
        FileOutputStream(imageFile).use { outputStream ->
            val format = if (imageType == ImageType.QR_CODE) {
                Bitmap.CompressFormat.PNG
            } else {
                Bitmap.CompressFormat.JPEG
            }
            val quality = if (imageType == ImageType.QR_CODE) 100 else 90

            bitmap.compress(format, quality, outputStream)
            outputStream.flush()
        }

        return imageFile.absolutePath
    }

    /**
     * Guarda una imagen asociada a una visita específica (snapshot de auditoría).
     * Las fotos se almacenan en visits/{visitId}/ y NUNCA se sobreescriben.
     *
     * @param context   Contexto de la aplicación
     * @param bitmap    Imagen a guardar
     * @param visitId   ID único de la visita
     * @param imageType Tipo de imagen (PROFILE, DOCUMENT_FRONT, DOCUMENT_BACK)
     * @return Path absoluto del archivo guardado
     */
    fun saveImageForVisit(
        context: Context,
        bitmap: Bitmap,
        visitId: String,
        imageType: ImageType
    ): String {
        val visitDir = File(context.filesDir, "visits/$visitId")
        if (!visitDir.exists()) visitDir.mkdirs()

        val imageFile = File(visitDir, imageType.filename)
        FileOutputStream(imageFile).use { out ->
            val format  = if (imageType == ImageType.QR_CODE) Bitmap.CompressFormat.PNG
                          else Bitmap.CompressFormat.JPEG
            val quality = if (imageType == ImageType.QR_CODE) 100 else 90
            bitmap.compress(format, quality, out)
            out.flush()
        }
        return imageFile.absolutePath
    }

    /**
     * Guarda una imagen para una visita (como QR).
     *
     * @param context Contexto de la aplicación
     * @param bitmap Imagen a guardar
     * @param visitId ID de la visita
     * @return Path completo del archivo guardado
     */
    fun saveVisitImage(
        context: Context,
        bitmap: Bitmap,
        visitId: String
    ): String {
        // Crear directorio para visitas si no existe
        val visitsDir = File(context.filesDir, "visits")
        if (!visitsDir.exists()) {
            visitsDir.mkdirs()
        }

        // Crear archivo
        val imageFile = File(visitsDir, "$visitId.png")

        // Guardar bitmap
        FileOutputStream(imageFile).use { outputStream ->
            bitmap.compress(Bitmap.CompressFormat.PNG, 100, outputStream)
            outputStream.flush()
        }

        return imageFile.absolutePath
    }

    /**
     * Obtiene el path de una imagen guardada.
     *
     * @param context Contexto de la aplicación
     * @param personId ID de la persona
     * @param imageType Tipo de imagen
     * @return Path del archivo o null si no existe
     */
    fun getImagePath(
        context: Context,
        personId: String,
        imageType: ImageType
    ): String? {
        val imageFile = File(context.filesDir, "visitors/$personId/${imageType.filename}")
        return if (imageFile.exists()) {
            imageFile.absolutePath
        } else {
            null
        }
    }

    /**
     * Elimina todas las imágenes de una persona.
     *
     * @param context Contexto de la aplicación
     * @param personId ID de la persona
     * @return true si se eliminaron correctamente
     */
    fun deletePersonImages(
        context: Context,
        personId: String
    ): Boolean {
        val personDir = File(context.filesDir, "visitors/$personId")
        return if (personDir.exists()) {
            personDir.deleteRecursively()
        } else {
            false
        }
    }

    /**
     * Obtiene el tamaño total de almacenamiento usado por las imágenes.
     *
     * @param context Contexto de la aplicación
     * @return Tamaño en bytes
     */
    fun getTotalStorageSize(context: Context): Long {
        val visitorsDir = File(context.filesDir, "visitors")
        val visitsDir = File(context.filesDir, "visits")

        var totalSize = 0L

        if (visitorsDir.exists()) {
            totalSize += visitorsDir.walkTopDown().filter { it.isFile }.map { it.length() }.sum()
        }

        if (visitsDir.exists()) {
            totalSize += visitsDir.walkTopDown().filter { it.isFile }.map { it.length() }.sum()
        }

        return totalSize
    }
}

package com.eflglobal.visitorsapp.data.local

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.sqlite.db.SupportSQLiteDatabase
import com.eflglobal.visitorsapp.data.local.dao.OcrMetricDao
import com.eflglobal.visitorsapp.data.local.dao.PersonDao
import com.eflglobal.visitorsapp.data.local.dao.StationDao
import com.eflglobal.visitorsapp.data.local.dao.VisitDao
import com.eflglobal.visitorsapp.data.local.dao.VisitReasonDao
import com.eflglobal.visitorsapp.data.local.entity.OcrMetricEntity
import com.eflglobal.visitorsapp.data.local.entity.PersonEntity
import com.eflglobal.visitorsapp.data.local.entity.StationEntity
import com.eflglobal.visitorsapp.data.local.entity.VisitEntity
import com.eflglobal.visitorsapp.data.local.entity.VisitReasonEntity
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

@Database(
    entities = [
        PersonEntity::class,
        VisitEntity::class,
        StationEntity::class,
        VisitReasonEntity::class,
        OcrMetricEntity::class
    ],
    version = 4,
    exportSchema = true
)
abstract class AppDatabase : RoomDatabase() {

    abstract fun personDao(): PersonDao
    abstract fun visitDao(): VisitDao
    abstract fun stationDao(): StationDao
    abstract fun visitReasonDao(): VisitReasonDao
    abstract fun ocrMetricDao(): OcrMetricDao

    companion object {
        private const val DATABASE_NAME = "visitors_app_database"

        /** Standard visit reason seed data (language-neutral keys). */
        val DEFAULT_VISIT_REASONS = listOf(
            VisitReasonEntity("VISITOR",        "Visitante",        "Visitor",        1),
            VisitReasonEntity("DRIVER",         "Conductor",        "Driver",         2),
            VisitReasonEntity("CONTRACTOR",     "Contratista",      "Contractor",     3),
            VisitReasonEntity("TEMPORARY_STAFF","Personal Temporal","Temporary Staff",4),
            VisitReasonEntity("DELIVERY",       "Entrega",          "Delivery",       5),
            VisitReasonEntity("VENDOR",         "Proveedor",        "Vendor",         6),
            VisitReasonEntity("OTHER",          "Otro",             "Other",          7)
        )

        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    DATABASE_NAME
                )
                    .fallbackToDestructiveMigration()
                    .addCallback(object : Callback() {
                        override fun onCreate(db: SupportSQLiteDatabase) {
                            super.onCreate(db)
                            // Seed visit reasons on first creation
                            INSTANCE?.let { database ->
                                CoroutineScope(Dispatchers.IO).launch {
                                    database.visitReasonDao().insertReasons(DEFAULT_VISIT_REASONS)
                                }
                            }
                        }
                    })
                    .build()

                INSTANCE = instance

                // Also seed if table is empty (handles first-run after fallbackToDestructiveMigration)
                CoroutineScope(Dispatchers.IO).launch {
                    if (instance.visitReasonDao().count() == 0) {
                        instance.visitReasonDao().insertReasons(DEFAULT_VISIT_REASONS)
                    }
                }

                instance
            }
        }

        // Método para testing
        fun getInMemoryDatabase(context: Context): AppDatabase {
            return Room.inMemoryDatabaseBuilder(
                context.applicationContext,
                AppDatabase::class.java
            )
                .allowMainThreadQueries()
                .build()
        }
    }
}

package com.eflglobal.visitorsapp.data.local

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.room.migration.Migration
import androidx.sqlite.db.SupportSQLiteDatabase
import com.eflglobal.visitorsapp.data.local.dao.OcrMetricDao
import com.eflglobal.visitorsapp.data.local.dao.PersonDao
import com.eflglobal.visitorsapp.data.local.dao.StationDao
import com.eflglobal.visitorsapp.data.local.dao.VisitDao
import com.eflglobal.visitorsapp.data.local.dao.VisitReasonDao
import com.eflglobal.visitorsapp.data.local.entity.OcrMetricEntity
import com.eflglobal.visitorsapp.data.local.entity.PersonEntity
import com.eflglobal.visitorsapp.data.local.entity.StationEntity
import com.eflglobal.visitorsapp.data.local.entity.VisitEntity
import com.eflglobal.visitorsapp.data.local.entity.VisitReasonEntity
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

@Database(
    entities = [
        PersonEntity::class,
        VisitEntity::class,
        StationEntity::class,
        VisitReasonEntity::class,
        OcrMetricEntity::class
    ],
    version = 5,
    exportSchema = true
)
abstract class AppDatabase : RoomDatabase() {

    abstract fun personDao(): PersonDao
    abstract fun visitDao(): VisitDao
    abstract fun stationDao(): StationDao
    abstract fun visitReasonDao(): VisitReasonDao
    abstract fun ocrMetricDao(): OcrMetricDao

    companion object {
        private const val DATABASE_NAME = "visitors_app_database"

        /** Standard visit reason seed data (language-neutral keys). */
        val DEFAULT_VISIT_REASONS = listOf(
            VisitReasonEntity("VISITOR",        "Visitante",        "Visitor",        1),
            VisitReasonEntity("DRIVER",         "Conductor",        "Driver",         2),
            VisitReasonEntity("CONTRACTOR",     "Contratista",      "Contractor",     3),
            VisitReasonEntity("TEMPORARY_STAFF","Personal Temporal","Temporary Staff",4),
            VisitReasonEntity("DELIVERY",       "Entrega",          "Delivery",       5),
            VisitReasonEntity("VENDOR",         "Proveedor",        "Vendor",         6),
            VisitReasonEntity("OTHER",          "Otro",             "Other",          7)
        )

        /**
         * Migration 4 → 5: adds per-visit photo snapshot columns to the visits table.
         * All existing rows get NULL values (no data loss).
         */
        val MIGRATION_4_5 = object : Migration(4, 5) {
            override fun migrate(db: SupportSQLiteDatabase) {
                db.execSQL("ALTER TABLE visits ADD COLUMN visitProfilePhotoPath TEXT")
                db.execSQL("ALTER TABLE visits ADD COLUMN visitDocumentFrontPath TEXT")
                db.execSQL("ALTER TABLE visits ADD COLUMN visitDocumentBackPath TEXT")
            }
        }

        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    DATABASE_NAME
                )
                    .addMigrations(MIGRATION_4_5)
                    .fallbackToDestructiveMigration()
                    .addCallback(object : Callback() {
                        override fun onCreate(db: SupportSQLiteDatabase) {
                            super.onCreate(db)
                            // Seed visit reasons on first creation
                            INSTANCE?.let { database ->
                                CoroutineScope(Dispatchers.IO).launch {
                                    database.visitReasonDao().insertReasons(DEFAULT_VISIT_REASONS)
                                }
                            }
                        }
                    })
                    .build()

                INSTANCE = instance

                // Also seed if table is empty (handles first-run after fallbackToDestructiveMigration)
                CoroutineScope(Dispatchers.IO).launch {
                    if (instance.visitReasonDao().count() == 0) {
                        instance.visitReasonDao().insertReasons(DEFAULT_VISIT_REASONS)
                    }
                }

                instance
            }
        }

        // Método para testing
        fun getInMemoryDatabase(context: Context): AppDatabase {
            return Room.inMemoryDatabaseBuilder(
                context.applicationContext,
                AppDatabase::class.java
            )
                .allowMainThreadQueries()
                .build()
        }
    }
}

package com.eflglobal.visitorsapp.data.local.dao

import androidx.room.*
import com.eflglobal.visitorsapp.data.local.entity.VisitEntity
import kotlinx.coroutines.flow.Flow

/** Simple projection for the reason-count aggregate query. */
data class ReasonCount(
    val visitReason: String,
    val cnt: Int
)

/** Visit with person information for display */
data class VisitWithPersonDto(
    val visitId: String,
    val personId: String,
    val stationId: String?,
    val visitingPersonName: String,
    val visitorType: String,
    val visitReason: String,
    val visitReasonCustom: String?,
    val entryDate: Long,
    val exitDate: Long?,
    val qrCodeValue: String,
    val isSynced: Boolean,
    val lastSyncAt: Long?,
    val personFirstName: String,
    val personLastName: String,
    val personCompany: String?,
    val personProfilePhotoPath: String?,
    val personDocumentFrontPath: String?,
    val personDocumentBackPath: String?
)

@Dao
interface VisitDao {

    // ===== INSERT =====
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertVisit(visit: VisitEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertVisits(visits: List<VisitEntity>)

    // ===== UPDATE =====
    @Update
    suspend fun updateVisit(visit: VisitEntity)

    @Query("UPDATE visits SET exitDate = :exitDate WHERE visitId = :visitId")
    suspend fun updateExitDate(visitId: String, exitDate: Long)

    @Query("UPDATE visits SET isSynced = :isSynced, lastSyncAt = :syncTime WHERE visitId = :visitId")
    suspend fun updateSyncStatus(visitId: String, isSynced: Boolean, syncTime: Long)

    // ===== DELETE =====
    @Delete
    suspend fun deleteVisit(visit: VisitEntity)

    @Query("DELETE FROM visits WHERE visitId = :visitId")
    suspend fun deleteVisitById(visitId: String)

    // ===== QUERY - Individual =====
    @Query("SELECT * FROM visits WHERE visitId = :visitId")
    suspend fun getVisitById(visitId: String): VisitEntity?

    @Query("SELECT * FROM visits WHERE visitId = :visitId")
    fun getVisitByIdFlow(visitId: String): Flow<VisitEntity?>

    @Query("SELECT * FROM visits WHERE qrCodeValue = :qrCode LIMIT 1")
    suspend fun getVisitByQRCode(qrCode: String): VisitEntity?

    // ===== QUERY - Por Persona =====
    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC")
    suspend fun getVisitsByPersonId(personId: String): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC")
    fun getVisitsByPersonIdFlow(personId: String): Flow<List<VisitEntity>>

    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC LIMIT 1")
    suspend fun getLastVisitByPersonId(personId: String): VisitEntity?

    // ===== QUERY - Visitas Activas (sin salida) =====
    @Query("SELECT * FROM visits WHERE exitDate IS NULL ORDER BY entryDate DESC")
    suspend fun getActiveVisits(): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE exitDate IS NULL ORDER BY entryDate DESC")
    fun getActiveVisitsFlow(): Flow<List<VisitEntity>>

    @Query("SELECT COUNT(*) FROM visits WHERE exitDate IS NULL")
    suspend fun getActiveVisitsCount(): Int

    @Query("SELECT COUNT(*) FROM visits WHERE exitDate IS NULL")
    fun getActiveVisitsCountFlow(): Flow<Int>

    @Query("""
        SELECT v.* FROM visits v
        INNER JOIN persons p ON v.personId = p.personId
        WHERE v.exitDate IS NULL 
        AND (
            p.firstName  LIKE '%' || :query || '%'
            OR p.lastName   LIKE '%' || :query || '%'
            OR v.visitingPersonName LIKE '%' || :query || '%'
        )
        ORDER BY v.entryDate DESC
    """)
    suspend fun searchActiveVisits(query: String): List<VisitEntity>

    // ===== QUERY - Por razón de visita =====
    @Query("SELECT * FROM visits WHERE visitReason = :reason ORDER BY entryDate DESC")
    suspend fun getVisitsByReason(reason: String): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE visitReason = :reason ORDER BY entryDate DESC")
    fun getVisitsByReasonFlow(reason: String): Flow<List<VisitEntity>>

    /** Returns all OTHER visits including their custom description. */
    @Query("SELECT * FROM visits WHERE visitReason = 'OTHER' ORDER BY entryDate DESC")
    suspend fun getOtherVisits(): List<VisitEntity>

    /** Count visits grouped by reason (for statistics / dashboard). */
    @Query("SELECT visitReason, COUNT(*) as cnt FROM visits GROUP BY visitReason")
    suspend fun countVisitsByReason(): List<ReasonCount>

    /** Active visits filtered by reason. */
    @Query("""
        SELECT * FROM visits 
        WHERE exitDate IS NULL AND visitReason = :reason 
        ORDER BY entryDate DESC
    """)
    suspend fun getActiveVisitsByReason(reason: String): List<VisitEntity>

    // ===== QUERY - Por Fecha =====

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    suspend fun getVisitsByDateRange(startDate: Long, endDate: Long): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    fun getVisitsByDateRangeFlow(startDate: Long, endDate: Long): Flow<List<VisitEntity>>

    // Visitas del día actual
    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay AND entryDate <= :endOfDay
        ORDER BY entryDate DESC
    """)
    suspend fun getTodayVisits(startOfDay: Long, endOfDay: Long): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay AND entryDate <= :endOfDay
        ORDER BY entryDate DESC
    """)
    fun getTodayVisitsFlow(startOfDay: Long, endOfDay: Long): Flow<List<VisitEntity>>

    // Visitas activas del día (para checkout manual)
    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay 
        AND entryDate <= :endOfDay
        AND exitDate IS NULL
        ORDER BY entryDate DESC
    """)
    suspend fun getTodayActiveVisits(startOfDay: Long, endOfDay: Long): List<VisitEntity>

    // ===== QUERY - Por Estación =====
    @Query("SELECT * FROM visits WHERE stationId = :stationId ORDER BY entryDate DESC")
    suspend fun getVisitsByStationId(stationId: String): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE stationId = :stationId 
        AND entryDate >= :startDate 
        AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    suspend fun getVisitsByStationAndDateRange(
        stationId: String,
        startDate: Long,
        endDate: Long
    ): List<VisitEntity>

    // ===== QUERY - Por Estación con JOIN =====
    @Query("""
        SELECT 
            v.visitId, v.personId, v.stationId, v.visitingPersonName,
            v.visitorType, v.visitReason, v.visitReasonCustom,
            v.entryDate, v.exitDate, v.qrCodeValue, v.isSynced, v.lastSyncAt,
            p.firstName  AS personFirstName,
            p.lastName   AS personLastName,
            p.company    AS personCompany,
            p.profilePhotoPath   AS personProfilePhotoPath,
            p.documentFrontPath  AS personDocumentFrontPath,
            p.documentBackPath   AS personDocumentBackPath
        FROM visits v
        INNER JOIN persons p ON v.personId = p.personId
        WHERE v.stationId = :stationId 
        ORDER BY v.entryDate DESC
    """)
    suspend fun getVisitsWithPersonInfoByStationId(stationId: String): List<VisitWithPersonDto>

    // ===== QUERY - Todas las visitas =====
    @Query("SELECT * FROM visits ORDER BY entryDate DESC")
    suspend fun getAllVisits(): List<VisitEntity>

    @Query("SELECT * FROM visits ORDER BY entryDate DESC")
    fun getAllVisitsFlow(): Flow<List<VisitEntity>>

    @Query("SELECT * FROM visits ORDER BY entryDate DESC LIMIT :limit")
    suspend fun getRecentVisits(limit: Int = 100): List<VisitEntity>

    // ===== QUERY - Sincronización =====
    @Query("SELECT * FROM visits WHERE isSynced = 0 ORDER BY createdAt ASC")
    suspend fun getUnsyncedVisits(): List<VisitEntity>

    @Query("SELECT COUNT(*) FROM visits WHERE isSynced = 0")
    suspend fun getUnsyncedCount(): Int

    @Query("SELECT COUNT(*) FROM visits WHERE isSynced = 0")
    fun getUnsyncedCountFlow(): Flow<Int>

    // ===== QUERY - Estadísticas =====
    @Query("SELECT COUNT(*) FROM visits")
    suspend fun getTotalVisitsCount(): Int

    @Query("SELECT COUNT(*) FROM visits")
    fun getTotalVisitsCountFlow(): Flow<Int>

    @Query("""
        SELECT COUNT(*) FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
    """)
    suspend fun getVisitsCountByDateRange(startDate: Long, endDate: Long): Int

    @Query("SELECT COUNT(DISTINCT personId) FROM visits")
    suspend fun getUniqueVisitorsCount(): Int

    // ===== UTILITY =====
    @Query("DELETE FROM visits")
    suspend fun deleteAllVisits()

    @Query("DELETE FROM visits WHERE exitDate IS NOT NULL AND entryDate < :beforeDate")
    suspend fun deleteOldCompletedVisits(beforeDate: Long)
}

package com.eflglobal.visitorsapp.data.local.dao

import androidx.room.*
import com.eflglobal.visitorsapp.data.local.entity.VisitEntity
import kotlinx.coroutines.flow.Flow

/** Simple projection for the reason-count aggregate query. */
data class ReasonCount(
    val visitReason: String,
    val cnt: Int
)

/** Visit with person information for display */
data class VisitWithPersonDto(
    val visitId: String,
    val personId: String,
    val stationId: String?,
    val visitingPersonName: String,
    val visitorType: String,
    val visitReason: String,
    val visitReasonCustom: String?,
    val entryDate: Long,
    val exitDate: Long?,
    val qrCodeValue: String,
    val isSynced: Boolean,
    val lastSyncAt: Long?,
    // Person reference data
    val personFirstName: String,
    val personLastName: String,
    val personCompany: String?,
    val personProfilePhotoPath: String?,
    val personDocumentFrontPath: String?,
    val personDocumentBackPath: String?,
    // Visit-specific audit snapshots (nullable — null for pre-v5 records)
    val visitProfilePhotoPath: String?,
    val visitDocumentFrontPath: String?,
    val visitDocumentBackPath: String?
)

@Dao
interface VisitDao {

    // ===== INSERT =====
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertVisit(visit: VisitEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertVisits(visits: List<VisitEntity>)

    // ===== UPDATE =====
    @Update
    suspend fun updateVisit(visit: VisitEntity)

    @Query("UPDATE visits SET exitDate = :exitDate WHERE visitId = :visitId")
    suspend fun updateExitDate(visitId: String, exitDate: Long)

    @Query("UPDATE visits SET isSynced = :isSynced, lastSyncAt = :syncTime WHERE visitId = :visitId")
    suspend fun updateSyncStatus(visitId: String, isSynced: Boolean, syncTime: Long)

    // ===== DELETE =====
    @Delete
    suspend fun deleteVisit(visit: VisitEntity)

    @Query("DELETE FROM visits WHERE visitId = :visitId")
    suspend fun deleteVisitById(visitId: String)

    // ===== QUERY - Individual =====
    @Query("SELECT * FROM visits WHERE visitId = :visitId")
    suspend fun getVisitById(visitId: String): VisitEntity?

    @Query("SELECT * FROM visits WHERE visitId = :visitId")
    fun getVisitByIdFlow(visitId: String): Flow<VisitEntity?>

    @Query("SELECT * FROM visits WHERE qrCodeValue = :qrCode LIMIT 1")
    suspend fun getVisitByQRCode(qrCode: String): VisitEntity?

    // ===== QUERY - Por Persona =====
    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC")
    suspend fun getVisitsByPersonId(personId: String): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC")
    fun getVisitsByPersonIdFlow(personId: String): Flow<List<VisitEntity>>

    @Query("SELECT * FROM visits WHERE personId = :personId ORDER BY entryDate DESC LIMIT 1")
    suspend fun getLastVisitByPersonId(personId: String): VisitEntity?

    // ===== QUERY - Visitas Activas (sin salida) =====
    @Query("SELECT * FROM visits WHERE exitDate IS NULL ORDER BY entryDate DESC")
    suspend fun getActiveVisits(): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE exitDate IS NULL ORDER BY entryDate DESC")
    fun getActiveVisitsFlow(): Flow<List<VisitEntity>>

    @Query("SELECT COUNT(*) FROM visits WHERE exitDate IS NULL")
    suspend fun getActiveVisitsCount(): Int

    @Query("SELECT COUNT(*) FROM visits WHERE exitDate IS NULL")
    fun getActiveVisitsCountFlow(): Flow<Int>

    @Query("""
        SELECT v.* FROM visits v
        INNER JOIN persons p ON v.personId = p.personId
        WHERE v.exitDate IS NULL 
        AND (
            p.firstName  LIKE '%' || :query || '%'
            OR p.lastName   LIKE '%' || :query || '%'
            OR v.visitingPersonName LIKE '%' || :query || '%'
        )
        ORDER BY v.entryDate DESC
    """)
    suspend fun searchActiveVisits(query: String): List<VisitEntity>

    // ===== QUERY - Por razón de visita =====
    @Query("SELECT * FROM visits WHERE visitReason = :reason ORDER BY entryDate DESC")
    suspend fun getVisitsByReason(reason: String): List<VisitEntity>

    @Query("SELECT * FROM visits WHERE visitReason = :reason ORDER BY entryDate DESC")
    fun getVisitsByReasonFlow(reason: String): Flow<List<VisitEntity>>

    /** Returns all OTHER visits including their custom description. */
    @Query("SELECT * FROM visits WHERE visitReason = 'OTHER' ORDER BY entryDate DESC")
    suspend fun getOtherVisits(): List<VisitEntity>

    /** Count visits grouped by reason (for statistics / dashboard). */
    @Query("SELECT visitReason, COUNT(*) as cnt FROM visits GROUP BY visitReason")
    suspend fun countVisitsByReason(): List<ReasonCount>

    /** Active visits filtered by reason. */
    @Query("""
        SELECT * FROM visits 
        WHERE exitDate IS NULL AND visitReason = :reason 
        ORDER BY entryDate DESC
    """)
    suspend fun getActiveVisitsByReason(reason: String): List<VisitEntity>

    // ===== QUERY - Por Fecha =====

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    suspend fun getVisitsByDateRange(startDate: Long, endDate: Long): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    fun getVisitsByDateRangeFlow(startDate: Long, endDate: Long): Flow<List<VisitEntity>>

    // Visitas del día actual
    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay AND entryDate <= :endOfDay
        ORDER BY entryDate DESC
    """)
    suspend fun getTodayVisits(startOfDay: Long, endOfDay: Long): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay AND entryDate <= :endOfDay
        ORDER BY entryDate DESC
    """)
    fun getTodayVisitsFlow(startOfDay: Long, endOfDay: Long): Flow<List<VisitEntity>>

    // Visitas activas del día (para checkout manual)
    @Query("""
        SELECT * FROM visits 
        WHERE entryDate >= :startOfDay 
        AND entryDate <= :endOfDay
        AND exitDate IS NULL
        ORDER BY entryDate DESC
    """)
    suspend fun getTodayActiveVisits(startOfDay: Long, endOfDay: Long): List<VisitEntity>

    // ===== QUERY - Por Estación =====
    @Query("SELECT * FROM visits WHERE stationId = :stationId ORDER BY entryDate DESC")
    suspend fun getVisitsByStationId(stationId: String): List<VisitEntity>

    @Query("""
        SELECT * FROM visits 
        WHERE stationId = :stationId 
        AND entryDate >= :startDate 
        AND entryDate <= :endDate
        ORDER BY entryDate DESC
    """)
    suspend fun getVisitsByStationAndDateRange(
        stationId: String,
        startDate: Long,
        endDate: Long
    ): List<VisitEntity>

    // ===== QUERY - Por Estación con JOIN =====
    @Query("""
        SELECT 
            v.visitId, v.personId, v.stationId, v.visitingPersonName,
            v.visitorType, v.visitReason, v.visitReasonCustom,
            v.entryDate, v.exitDate, v.qrCodeValue, v.isSynced, v.lastSyncAt,
            v.visitProfilePhotoPath  AS visitProfilePhotoPath,
            v.visitDocumentFrontPath AS visitDocumentFrontPath,
            v.visitDocumentBackPath  AS visitDocumentBackPath,
            p.firstName  AS personFirstName,
            p.lastName   AS personLastName,
            p.company    AS personCompany,
            p.profilePhotoPath   AS personProfilePhotoPath,
            p.documentFrontPath  AS personDocumentFrontPath,
            p.documentBackPath   AS personDocumentBackPath
        FROM visits v
        INNER JOIN persons p ON v.personId = p.personId
        WHERE v.stationId = :stationId 
        ORDER BY v.entryDate DESC
    """)
    suspend fun getVisitsWithPersonInfoByStationId(stationId: String): List<VisitWithPersonDto>

    // ===== QUERY - Todas las visitas =====
    @Query("SELECT * FROM visits ORDER BY entryDate DESC")
    suspend fun getAllVisits(): List<VisitEntity>

    @Query("SELECT * FROM visits ORDER BY entryDate DESC")
    fun getAllVisitsFlow(): Flow<List<VisitEntity>>

    @Query("SELECT * FROM visits ORDER BY entryDate DESC LIMIT :limit")
    suspend fun getRecentVisits(limit: Int = 100): List<VisitEntity>

    // ===== QUERY - Sincronización =====
    @Query("SELECT * FROM visits WHERE isSynced = 0 ORDER BY createdAt ASC")
    suspend fun getUnsyncedVisits(): List<VisitEntity>

    @Query("SELECT COUNT(*) FROM visits WHERE isSynced = 0")
    suspend fun getUnsyncedCount(): Int

    @Query("SELECT COUNT(*) FROM visits WHERE isSynced = 0")
    fun getUnsyncedCountFlow(): Flow<Int>

    // ===== QUERY - Estadísticas =====
    @Query("SELECT COUNT(*) FROM visits")
    suspend fun getTotalVisitsCount(): Int

    @Query("SELECT COUNT(*) FROM visits")
    fun getTotalVisitsCountFlow(): Flow<Int>

    @Query("""
        SELECT COUNT(*) FROM visits 
        WHERE entryDate >= :startDate AND entryDate <= :endDate
    """)
    suspend fun getVisitsCountByDateRange(startDate: Long, endDate: Long): Int

    @Query("SELECT COUNT(DISTINCT personId) FROM visits")
    suspend fun getUniqueVisitorsCount(): Int

    // ===== UTILITY =====
    @Query("DELETE FROM visits")
    suspend fun deleteAllVisits()

    @Query("DELETE FROM visits WHERE exitDate IS NOT NULL AND entryDate < :beforeDate")
    suspend fun deleteOldCompletedVisits(beforeDate: Long)
}

