data class Visit( val visitId: String, val personId: String, val stationId: String?, val visitingPersonName: String,
/** * Who the visitor IS — "Yo soy un:" category. * One of: VISITOR, CONTRACTOR, VENDOR, DELIVERY, DRIVER, TEMPORARY_STAFF, OTHER */ val visitorType: String,
/** * WHY they are visiting — purpose/reason of the visit. * One of: VISITOR, DRIVER, CONTRACTOR, TEMPORARY_STAFF, DELIVERY, VENDOR, OTHER. */ val visitReason: String,
/** * Free-text description — populated only when [visitReason] == "OTHER". */ val visitReasonCustom: String?,
val entryDate: Long, val exitDate: Long?, val qrCodeValue: String,
/** * Immutable audit snapshots — photos captured at this specific visit. * Stored in visits/{visitId}/ folder, never overwritten by future visits. */ val visitProfilePhotoPath: String? = null, val visitDocumentFrontPath: String? = null, val visitDocumentBackPath: String? = null,
val isSynced: Boolean, val lastSyncAt: Long? )
/** Domain model for the visit_reasons lookup table. */ data class VisitReason( val reasonKey: String, val labelEs: String, val labelEn: String, val sortOrder: Int, val isActive: Boolean = true ) { fun label(lang: String) = if (lang == "es") labelEs else labelEn }
/** All standard visit reason keys as constants for safe comparisons. */ object VisitReasonKeys { const val VISITOR = "VISITOR" const val DRIVER = "DRIVER" const val CONTRACTOR = "CONTRACTOR" const val TEMPORARY_STAFF = "TEMPORARY_STAFF" const val DELIVERY = "DELIVERY" const val VENDOR = "VENDOR" const val OTHER = "OTHER" }

package com.eflglobal.visitorsapp.domain.usecase.visit
import com.eflglobal.visitorsapp.domain.model.Visit import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys import com.eflglobal.visitorsapp.domain.repository.StationRepository import com.eflglobal.visitorsapp.domain.repository.VisitRepository import java.util.UUID
/** * Use Case para crear una nueva visita. */ class CreateVisitUseCase( private val visitRepository: VisitRepository, private val stationRepository: StationRepository ) { suspend operator fun invoke( personId: String, visitingPersonName: String, visitorType: String, // "Yo soy un:" — who the visitor IS visitReason: String, // "Motivo de visita" — why they are visiting visitReasonCustom: String? = null // free-text only when visitReason == "OTHER" ): Result<Visit> { val stationId = stationRepository.getActiveStationId() val visitId = UUID.randomUUID().toString() val qrCode = visitRepository.generateQRCode(visitId)
val sanitisedCustom = if (visitReason == VisitReasonKeys.OTHER) visitReasonCustom?.trim()?.takeIf { it.isNotBlank() } else null
val visit = Visit( visitId = visitId, personId = personId, stationId = stationId, visitingPersonName = visitingPersonName, visitorType = visitorType, visitReason = visitReason, visitReasonCustom = sanitisedCustom, entryDate = System.currentTimeMillis(), exitDate = null, qrCodeValue = qrCode, isSynced = false, lastSyncAt = null )
return visitRepository.createVisit(visit) } }

package com.eflglobal.visitorsapp.domain.usecase.visit
import com.eflglobal.visitorsapp.domain.model.Visit import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys import com.eflglobal.visitorsapp.domain.repository.StationRepository import com.eflglobal.visitorsapp.domain.repository.VisitRepository import java.util.UUID
/** * Use Case para crear una nueva visita. */ class CreateVisitUseCase( private val visitRepository: VisitRepository, private val stationRepository: StationRepository ) { suspend operator fun invoke( personId: String, visitingPersonName: String, visitorType: String, visitReason: String, visitReasonCustom: String? = null, /** Pre-generated visitId — if null a new UUID is generated here. */ visitId: String? = null, /** Audit snapshot photos taken at this specific visit. */ visitProfilePhotoPath: String? = null, visitDocumentFrontPath: String? = null, visitDocumentBackPath: String? = null ): Result<Visit> { val stationId = stationRepository.getActiveStationId() val resolvedVisitId = visitId ?: UUID.randomUUID().toString() val qrCode = visitRepository.generateQRCode(resolvedVisitId)
val sanitisedCustom = if (visitReason == VisitReasonKeys.OTHER) visitReasonCustom?.trim()?.takeIf { it.isNotBlank() } else null
val visit = Visit( visitId = resolvedVisitId, personId = personId, stationId = stationId, visitingPersonName = visitingPersonName, visitorType = visitorType, visitReason = visitReason, visitReasonCustom = sanitisedCustom, entryDate = System.currentTimeMillis(), exitDate = null, qrCodeValue = qrCode, visitProfilePhotoPath = visitProfilePhotoPath, visitDocumentFrontPath = visitDocumentFrontPath, visitDocumentBackPath = visitDocumentBackPath, isSynced = false, lastSyncAt = null )
return visitRepository.createVisit(visit) } }

