import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.eflglobal.visitorsapp.R
import com.eflglobal.visitorsapp.core.utils.ImageSaver
import com.eflglobal.visitorsapp.data.local.AppDatabase
import com.eflglobal.visitorsapp.data.local.mapper.toDomain
import com.eflglobal.visitorsapp.domain.model.VisitReason
import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys
import com.eflglobal.visitorsapp.ui.components.CameraPermissionHandler
import com.eflglobal.visitorsapp.ui.components.CameraPreviewComposable
import com.eflglobal.visitorsapp.ui.theme.OrangePrimary
import com.eflglobal.visitorsapp.ui.theme.SlatePrimary
import com.eflglobal.visitorsapp.ui.viewmodel.RecurrentVisitViewModel
import com.eflglobal.visitorsapp.ui.viewmodel.RecurrentVisitUiState
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun RecurrentVisitDataScreen(
    visitorName: String = "",
    onContinue: () -> Unit,
    onBack: () -> Unit,
    viewModel: RecurrentVisitViewModel? = null,
    selectedLanguage: String = "es"
) {
    val context        = LocalContext.current
    val coroutineScope = rememberCoroutineScope()

    // ── Pre-fill: draft (edit flow) takes priority, then person DB data ───────
    val person = viewModel?.getSelectedPerson()
    val hasDraft = viewModel?.hasDraft == true

    // Draft has priority, then last visit data, then person data
    val lastVisitData = viewModel?.getLastVisit()

    var editFirstName by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftFirstName != null -> viewModel.draftFirstName!!
            lastVisitData != null -> person?.firstName ?: ""
            else -> person?.firstName ?: visitorName.substringBefore(" ")
        }
    ) }
    var editLastName  by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftLastName != null -> viewModel.draftLastName!!
            lastVisitData != null -> person?.lastName ?: ""
            else -> person?.lastName ?: visitorName.substringAfter(" ", "")
        }
    ) }
    var editDoc       by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftDoc != null -> viewModel.draftDoc!!
            else -> person?.documentNumber ?: ""
        }
    ) }
    var editCompany   by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftCompany != null -> viewModel.draftCompany!!
            else -> person?.company ?: ""
        }
    ) }
    var editEmail     by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftEmail != null -> viewModel.draftEmail!!
            else -> person?.email ?: ""
        }
    ) }
    var editPhone     by remember(person?.personId, hasDraft) { mutableStateOf(
        when {
            hasDraft && viewModel?.draftPhone != null -> viewModel.draftPhone!!
            else -> person?.phoneNumber ?: ""
        }
    ) }

    // Load profile photo: new photo taken in this session wins, otherwise use stored person photo
    val effectivePhotoPath = viewModel?.profilePhotoPath ?: person?.profilePhotoPath
    var storedProfileBitmap by remember { mutableStateOf<Bitmap?>(null) }
    LaunchedEffect(effectivePhotoPath) {
        if (!effectivePhotoPath.isNullOrBlank()) {
            withContext(Dispatchers.IO) {
                runCatching { BitmapFactory.decodeFile(effectivePhotoPath) }.getOrNull()
            }?.let { storedProfileBitmap = it }
        }
    }

    // ── Photo ─────────────────────────────────────────────────────────────────
    var photoTaken       by remember { mutableStateOf(false) }
    var isCapturing      by remember { mutableStateOf(false) }
    var capturedBitmap   by remember { mutableStateOf<Bitmap?>(null) }

    // Show stored photo until a new one is taken
    val displayBitmap = capturedBitmap ?: storedProfileBitmap

    // ── Visit reason ──────────────────────────────────────────────────────────
    val visitReasons = remember { mutableStateListOf<VisitReason>() }
    LaunchedEffect(Unit) {
        val reasons = withContext(Dispatchers.IO) {
            AppDatabase.getInstance(context).visitReasonDao().getAllActiveReasons()
        }.map { it.toDomain() }
        visitReasons.clear()
        visitReasons.addAll(reasons)
    }
    var selectedReason   by remember { mutableStateOf<VisitReason?>(
        if (hasDraft && viewModel?.draftVisitReasonKey != null) {
            visitReasons.firstOrNull { it.reasonKey == viewModel.draftVisitReasonKey }
        } else null
    ) }
    var reasonExpanded   by remember { mutableStateOf(false) }
    var customReasonText by remember { mutableStateOf(
        if (hasDraft) viewModel?.draftVisitReasonCustom ?: ""
        else ""
    ) }
    val isOtherSelected  = selectedReason?.reasonKey == VisitReasonKeys.OTHER

    // Restore selectedReason from draft once the list is populated
    LaunchedEffect(visitReasons.size) {
        if (visitReasons.isNotEmpty() && selectedReason == null && hasDraft) {
            val draftKey = viewModel?.draftVisitReasonKey
            if (!draftKey.isNullOrBlank()) {
                selectedReason = visitReasons.firstOrNull { it.reasonKey == draftKey }
            }
        }
    }

    // ── Who visiting ─────────────────────────────────────────────────────────
    var visitingPerson by remember { mutableStateOf(
        when {
            hasDraft && viewModel?.draftVisitingPerson != null -> viewModel.draftVisitingPerson!!
            lastVisitData != null -> lastVisitData.visitingPersonName
            else -> ""
        }
    ) }

    // Reactively update visitingPerson and selectedReason when last visit pre-fill arrives
    // (only if no draft exists and user hasn't manually entered a value yet)
    val lastVisitPreFill by (viewModel?.lastVisitPreFill ?: return).collectAsState()
    LaunchedEffect(lastVisitPreFill) {
        val last = lastVisitPreFill ?: return@LaunchedEffect
        // Only apply pre-fill if user hasn't manually entered a value yet AND no draft exists
        if (visitingPerson.isBlank() && !hasDraft) {
            visitingPerson = last.visitingPersonName
        }
        // Apply visit reason pre-fill if not already set by a draft
        if (selectedReason == null && visitReasons.isNotEmpty() && !hasDraft) {
            selectedReason = visitReasons.firstOrNull { it.reasonKey == last.visitReason }
            if (last.visitReason == VisitReasonKeys.OTHER && last.visitReasonCustom != null && customReasonText.isBlank()) {
                customReasonText = last.visitReasonCustom ?: ""
            }
        }
    }

    // Also re-apply when visitReasons list loads after lastVisitPreFill was already set
    LaunchedEffect(visitReasons.size, lastVisitPreFill) {
        val last = lastVisitPreFill ?: return@LaunchedEffect
        if (visitReasons.isNotEmpty() && selectedReason == null) {
            selectedReason = visitReasons.firstOrNull { it.reasonKey == last.visitReason }
            if (last.visitReason == VisitReasonKeys.OTHER && last.visitReasonCustom != null && customReasonText.isBlank()) {
                customReasonText = last.visitReasonCustom ?: ""
            }
        }
    }

    // ── UiState → navigate on success ────────────────────────────────────────
    val uiState by (viewModel?.uiState ?: return).collectAsState()
    LaunchedEffect(uiState) {
        if (uiState is RecurrentVisitUiState.Success) onContinue()
    }

    val canSubmit = visitingPerson.isNotBlank()
        && selectedReason != null
        && (!isOtherSelected || customReasonText.isNotBlank())
        && uiState !is RecurrentVisitUiState.Loading

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.visit_information), fontSize = 18.sp) },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = stringResource(R.string.back))
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = MaterialTheme.colorScheme.surface)
            )
        }
    ) { padding ->
        Box(modifier = Modifier.fillMaxSize().padding(padding)) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(MaterialTheme.colorScheme.background)
                .verticalScroll(rememberScrollState())
                .padding(horizontal = 24.dp, vertical = 16.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(20.dp),
                verticalAlignment = Alignment.Top
            ) {
                // ════════════════════════════════════════════
                // LEFT COLUMN — Registered Visitor Info (read-only)
                // ════════════════════════════════════════════
                Column(modifier = Modifier.weight(1f)) {

                    Text(
                        text       = stringResource(R.string.registered_visitor),
                        style      = MaterialTheme.typography.titleMedium.copy(fontSize = 16.sp),
                        fontWeight = FontWeight.SemiBold,
                        color      = SlatePrimary,
                        modifier   = Modifier.padding(bottom = 12.dp)
                    )

                    // ── Verified badge ────────────────────────────────────────
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(OrangePrimary.copy(alpha = 0.08f), RoundedCornerShape(8.dp))
                            .border(1.dp, OrangePrimary.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
                            .padding(horizontal = 12.dp, vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Icon(Icons.Default.CheckCircle, null, tint = OrangePrimary, modifier = Modifier.size(16.dp))
                        Text(
                            stringResource(R.string.document_verified),
                            style = MaterialTheme.typography.bodySmall.copy(fontSize = 11.sp),
                            color = OrangePrimary, fontWeight = FontWeight.SemiBold
                        )
                    }

                    Spacer(Modifier.height(12.dp))

                    // First name — editable
                    OutlinedTextField(
                        value         = editFirstName,
                        onValueChange = { editFirstName = it },
                        label         = { Text(stringResource(R.string.first_name), fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary,
                            unfocusedBorderColor = if (editFirstName.isNotBlank()) OrangePrimary.copy(alpha = 0.6f)
                                                   else MaterialTheme.colorScheme.outline
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                    Spacer(Modifier.height(10.dp))

                    // Last name — editable
                    OutlinedTextField(
                        value         = editLastName,
                        onValueChange = { editLastName = it },
                        label         = { Text(stringResource(R.string.last_name), fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary,
                            unfocusedBorderColor = if (editLastName.isNotBlank()) OrangePrimary.copy(alpha = 0.6f)
                                                   else MaterialTheme.colorScheme.outline
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                    Spacer(Modifier.height(10.dp))

                    // Document number — optional, editable
                    OutlinedTextField(
                        value         = editDoc,
                        onValueChange = { editDoc = it },
                        label         = { Text(stringResource(R.string.document_number) + " (" + stringResource(R.string.optional) + ")", fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                    Spacer(Modifier.height(10.dp))

                    // Company — optional, editable
                    OutlinedTextField(
                        value         = editCompany,
                        onValueChange = { editCompany = it },
                        label         = { Text(stringResource(R.string.company) + " (" + stringResource(R.string.optional) + ")", fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                    Spacer(Modifier.height(10.dp))

                    // Email — editable
                    OutlinedTextField(
                        value         = editEmail,
                        onValueChange = { editEmail = it },
                        label         = { Text(stringResource(R.string.email), fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                    Spacer(Modifier.height(10.dp))

                    // Phone — editable
                    OutlinedTextField(
                        value         = editPhone,
                        onValueChange = { editPhone = it },
                        label         = { Text(stringResource(R.string.phone), fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor   = OrangePrimary,
                            focusedLabelColor    = OrangePrimary
                        ),
                        singleLine = true,
                        textStyle  = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )
                }

                // ════════════════════════════════════════════
                // RIGHT COLUMN — Who visiting + Visit Reason + Photo
                // ════════════════════════════════════════════
                Column(modifier = Modifier.weight(1f)) {

                    // ── Who are you visiting ──────────────────────────────────
                    OutlinedTextField(
                        value         = visitingPerson,
                        onValueChange = { visitingPerson = it },
                        label         = { Text(stringResource(R.string.who_visiting), fontSize = 11.sp) },
                        placeholder   = { Text(stringResource(R.string.enter_who_visiting), fontSize = 11.sp) },
                        modifier      = Modifier.fillMaxWidth(),
                        shape         = RoundedCornerShape(12.dp),
                        colors        = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = OrangePrimary,
                            focusedLabelColor  = OrangePrimary,
                            unfocusedBorderColor = if (visitingPerson.isNotBlank()) OrangePrimary.copy(alpha = 0.6f)
                                                   else MaterialTheme.colorScheme.outline
                        ),
                        singleLine  = true,
                        textStyle   = LocalTextStyle.current.copy(fontSize = 13.sp)
                    )

                    Spacer(Modifier.height(16.dp))

                    // ── Visit Reason ──────────────────────────────────────────
                    Text(
                        text       = stringResource(R.string.visit_reason),
                        style      = MaterialTheme.typography.titleMedium.copy(fontSize = 16.sp),
                        fontWeight = FontWeight.SemiBold,
                        color      = SlatePrimary,
                        modifier   = Modifier.padding(bottom = 12.dp)
                    )

                    if (visitReasons.isEmpty()) {
                        Box(modifier = Modifier.fillMaxWidth().padding(vertical = 16.dp), contentAlignment = Alignment.Center) {
                            CircularProgressIndicator(color = OrangePrimary, strokeWidth = 3.dp, modifier = Modifier.size(28.dp))
                        }
                    } else {
                        ExposedDropdownMenuBox(
                            expanded         = reasonExpanded,
                            onExpandedChange = { reasonExpanded = !reasonExpanded },
                            modifier         = Modifier.fillMaxWidth()
                        ) {
                            OutlinedTextField(
                                value         = selectedReason?.label(selectedLanguage) ?: stringResource(R.string.select_visit_reason),
                                onValueChange = {},
                                readOnly      = true,
                                label         = { Text(stringResource(R.string.visit_reason), fontSize = 11.sp) },
                                trailingIcon  = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = reasonExpanded) },
                                modifier      = Modifier.menuAnchor(MenuAnchorType.PrimaryNotEditable).fillMaxWidth(),
                                shape         = RoundedCornerShape(12.dp),
                                colors        = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor   = OrangePrimary,
                                    focusedLabelColor    = OrangePrimary,
                                    unfocusedBorderColor = if (selectedReason != null) OrangePrimary.copy(alpha = 0.6f)
                                                           else MaterialTheme.colorScheme.outline
                                ),
                                textStyle = LocalTextStyle.current.copy(fontSize = 13.sp)
                            )
                            ExposedDropdownMenu(expanded = reasonExpanded, onDismissRequest = { reasonExpanded = false }) {
                                visitReasons.forEach { reason ->
                                    DropdownMenuItem(
                                        text = {
                                            Text(
                                                reason.label(selectedLanguage), fontSize = 13.sp,
                                                fontWeight = if (reason.reasonKey == VisitReasonKeys.OTHER) FontWeight.SemiBold else FontWeight.Normal
                                            )
                                        },
                                        onClick = {
                                            selectedReason = reason
                                            reasonExpanded = false
                                            if (reason.reasonKey != VisitReasonKeys.OTHER) customReasonText = ""
                                            viewModel?.setVisitReason(reason.reasonKey)
                                        }
                                    )
                                }
                            }
                        }

                        // "Other" free-text
                        AnimatedVisibility(visible = isOtherSelected, enter = expandVertically(), exit = shrinkVertically()) {
                            Column(modifier = Modifier.padding(top = 8.dp)) {
                                OutlinedTextField(
                                    value         = customReasonText,
                                    onValueChange = {
                                        customReasonText = it
                                        viewModel?.setVisitReason(VisitReasonKeys.OTHER, it)
                                    },
                                    label         = { Text(stringResource(R.string.other_specify), fontSize = 11.sp) },
                                    modifier      = Modifier.fillMaxWidth(),
                                    shape         = RoundedCornerShape(12.dp),
                                    colors        = OutlinedTextFieldDefaults.colors(focusedBorderColor = OrangePrimary, focusedLabelColor = OrangePrimary),
                                    maxLines      = 3,
                                    textStyle     = LocalTextStyle.current.copy(fontSize = 13.sp)
                                )
                                if (customReasonText.isBlank()) {
                                    Text(
                                        text     = "* " + stringResource(R.string.required_field),
                                        style    = MaterialTheme.typography.bodySmall.copy(fontSize = 10.sp),
                                        color    = MaterialTheme.colorScheme.error,
                                        modifier = Modifier.padding(start = 12.dp, top = 2.dp)
                                    )
                                }
                            }
                        }
                    }

                    Spacer(Modifier.height(20.dp))

                    // ── Personal Photo ────────────────────────────────────────
                    Text(
                        text       = stringResource(R.string.personal_photo),
                        style      = MaterialTheme.typography.titleMedium.copy(fontSize = 16.sp),
                        fontWeight = FontWeight.SemiBold,
                        color      = SlatePrimary,
                        modifier   = Modifier.padding(bottom = 12.dp)
                    )

                    Card(
                        onClick   = { if (!photoTaken) isCapturing = true },
                        modifier  = Modifier.fillMaxWidth().aspectRatio(2f),
                        shape     = RoundedCornerShape(16.dp),
                        colors    = CardDefaults.cardColors(
                            containerColor = if (displayBitmap != null) OrangePrimary.copy(alpha = 0.08f)
                                             else MaterialTheme.colorScheme.surfaceVariant
                        ),
                        border = if (displayBitmap != null) BorderStroke(2.dp, OrangePrimary)
                                 else BorderStroke(1.5.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.3f))
                    ) {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            if (displayBitmap != null) {
                                Image(
                                    bitmap             = displayBitmap.asImageBitmap(),
                                    contentDescription = null,
                                    contentScale       = ContentScale.FillWidth,
                                    modifier           = Modifier.fillMaxSize().clip(RoundedCornerShape(16.dp))
                                )
                                Box(modifier = Modifier.fillMaxSize().clip(RoundedCornerShape(16.dp))
                                    .background(OrangePrimary.copy(alpha = 0.12f)))
                                Box(
                                    modifier = Modifier.align(Alignment.TopEnd).padding(8.dp).size(28.dp)
                                        .background(OrangePrimary, CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(Icons.Default.CheckCircle, null, tint = androidx.compose.ui.graphics.Color.White, modifier = Modifier.size(20.dp))
                                }
                            } else {
                                Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                    Icon(Icons.Default.Portrait, null, tint = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.35f), modifier = Modifier.size(56.dp))
                                    Text(
                                        stringResource(R.string.take_photo),
                                        style = MaterialTheme.typography.bodySmall.copy(fontSize = 11.sp),
                                        color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.4f),
                                        textAlign = TextAlign.Center
                                    )
                                }
                            }
                        }
                    }

                    Spacer(Modifier.height(8.dp))

                    // Retake / take photo button
                    OutlinedButton(
                        onClick  = { isCapturing = true },
                        modifier = Modifier.fillMaxWidth().height(40.dp),
                        shape    = RoundedCornerShape(12.dp),
                        border   = BorderStroke(1.dp, OrangePrimary),
                        colors   = ButtonDefaults.outlinedButtonColors(contentColor = OrangePrimary)
                    ) {
                        Icon(Icons.Default.Portrait, null, modifier = Modifier.size(16.dp))
                        Spacer(Modifier.width(6.dp))
                        Text(
                            if (displayBitmap != null) stringResource(R.string.retake_photo) else stringResource(R.string.take_photo),
                            fontSize = 12.sp
                        )
                    }
                } // end right column
            } // end Row

            Spacer(Modifier.height(24.dp))

            // ── Continue button ───────────────────────────────────────────────
            Button(
                onClick  = {
                    // Persist all edits to ViewModel before navigating forward
                    viewModel?.saveDraft(
                        firstName         = editFirstName,
                        lastName          = editLastName,
                        doc               = editDoc,
                        company           = editCompany,
                        email             = editEmail,
                        phone             = editPhone,
                        visitingPerson    = visitingPerson,
                        visitReasonKey    = selectedReason?.reasonKey,
                        visitReasonCustom = if (isOtherSelected) customReasonText else null
                    )
                    viewModel?.setVisitReason(
                        selectedReason?.reasonKey ?: VisitReasonKeys.VISITOR,
                        if (isOtherSelected) customReasonText else null
                    )
                    viewModel?.createVisit(
                        visitingPersonName = visitingPerson,
                        editedFirstName    = editFirstName,
                        editedLastName     = editLastName,
                        editedCompany      = editCompany,
                        editedEmail        = editEmail,
                        editedPhone        = editPhone
                    )
                },
                enabled  = canSubmit,
                modifier = Modifier.fillMaxWidth().height(56.dp),
                colors   = ButtonDefaults.buttonColors(
                    containerColor         = OrangePrimary,
                    disabledContainerColor = MaterialTheme.colorScheme.surfaceVariant
                ),
                shape = RoundedCornerShape(12.dp)
            ) {
                if (uiState is RecurrentVisitUiState.Loading) {
                    CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary, strokeWidth = 2.5.dp)
                } else {
                    Text(stringResource(R.string.continue_btn), style = MaterialTheme.typography.titleMedium.copy(fontSize = 15.sp), fontWeight = FontWeight.SemiBold)
                }
            }

            if (uiState is RecurrentVisitUiState.Error) {
                Spacer(Modifier.height(8.dp))
                Text(
                    text     = (uiState as RecurrentVisitUiState.Error).message,
                    style    = MaterialTheme.typography.bodySmall,
                    color    = MaterialTheme.colorScheme.error,
                    textAlign = TextAlign.Center,
                    modifier = Modifier.fillMaxWidth()
                )
            }
        }

        // ── Selfie capture modal ──────────────────────────────────────────────
        if (isCapturing) {
            RecurrentSelfieCaptureModal(
                onDismiss       = { isCapturing = false },
                onPhotoCaptured = { bitmap ->
                    coroutineScope.launch {
                        try {
                            val savedPath = withContext(Dispatchers.IO) {
                                ImageSaver.saveImageForVisit(
                                    context   = context,
                                    bitmap    = bitmap,
                                    visitId   = viewModel?.getVisitId() ?: "visit_temp",
                                    imageType = ImageSaver.ImageType.PROFILE
                                )
                            }
                            // Notify ViewModel so the path is included in Success state
                            viewModel?.setProfilePhoto(savedPath)
                            capturedBitmap = bitmap
                            photoTaken     = true
                            isCapturing    = false
                        } catch (e: Exception) {
                            e.printStackTrace()
                            capturedBitmap = bitmap
                            photoTaken     = true
                            isCapturing    = false
                        }
                    }
                }
            )
        }
        } // end Box
    } // end Scaffold
}


// ── Selfie capture modal — AUTO countdown ────────────────────────────────────
@Composable
private fun RecurrentSelfieCaptureModal(
    onDismiss: () -> Unit,
    onPhotoCaptured: (Bitmap) -> Unit
) {
    var countdown     by remember { mutableStateOf(5) }
    var shouldCapture by remember { mutableStateOf(false) }
    var isProcessing  by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        while (countdown > 0) { delay(1000); countdown-- }
        shouldCapture = true
    }

    Box(modifier = Modifier.fillMaxSize().background(androidx.compose.ui.graphics.Color.Black)) {
        CameraPermissionHandler(onPermissionGranted = {}, onPermissionDenied = { onDismiss() }) {
            CameraPreviewComposable(
                onImageCaptured   = { bitmap -> isProcessing = true; onPhotoCaptured(bitmap) },
                onError           = { onDismiss() },
                lensFacing        = CameraSelector.LENS_FACING_FRONT,
                modifier          = Modifier.fillMaxSize(),
                shouldCapture     = shouldCapture,
                onCaptureComplete = { shouldCapture = false }
            )
        }

        // Top bar
        Row(
            modifier = Modifier.fillMaxWidth().padding(16.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment     = Alignment.CenterVertically
        ) {
            Text(
                text       = stringResource(R.string.personal_photo),
                style      = MaterialTheme.typography.titleLarge,
                fontWeight = FontWeight.Bold,
                color      = androidx.compose.ui.graphics.Color.White,
                modifier   = Modifier
                    .background(androidx.compose.ui.graphics.Color.Black.copy(alpha = 0.55f), RoundedCornerShape(10.dp))
                    .padding(horizontal = 14.dp, vertical = 10.dp)
            )
            if (!isProcessing) {
                IconButton(
                    onClick  = onDismiss,
                    modifier = Modifier.background(androidx.compose.ui.graphics.Color.Black.copy(alpha = 0.55f), CircleShape)
                ) {
                    Icon(Icons.Default.Close, contentDescription = stringResource(R.string.cancel), tint = androidx.compose.ui.graphics.Color.White)
                }
            }
        }

        // Face guide + countdown
        Column(
            modifier            = Modifier.fillMaxSize(),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            Box(
                modifier         = Modifier.size(240.dp).border(4.dp, OrangePrimary, CircleShape),
                contentAlignment = Alignment.Center
            ) {
                if (isProcessing) {
                    CircularProgressIndicator(color = OrangePrimary, modifier = Modifier.size(56.dp))
                } else if (countdown > 0) {
                    Box(
                        modifier         = Modifier.size(120.dp).background(androidx.compose.ui.graphics.Color.Black.copy(alpha = 0.65f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(countdown.toString(), style = MaterialTheme.typography.displayLarge, fontWeight = FontWeight.Bold, color = OrangePrimary, fontSize = 64.sp)
                    }
                }
            }
            Spacer(Modifier.height(24.dp))
            Text(
                text = when {
                    isProcessing  -> stringResource(R.string.verifying)
                    countdown > 0 -> stringResource(R.string.position_face)
                    else          -> stringResource(R.string.look_at_camera)
                },
                style     = MaterialTheme.typography.titleMedium,
                color     = androidx.compose.ui.graphics.Color.White,
                textAlign = TextAlign.Center,
                modifier  = Modifier
                    .background(androidx.compose.ui.graphics.Color.Black.copy(alpha = 0.55f), RoundedCornerShape(12.dp))
                    .padding(horizontal = 20.dp, vertical = 12.dp)
            )
        }
    }
}

package com.eflglobal.visitorsapp.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.eflglobal.visitorsapp.core.ocr.DocumentDataExtractor
import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys
import com.eflglobal.visitorsapp.domain.usecase.person.CreatePersonUseCase
import com.eflglobal.visitorsapp.domain.usecase.person.GetPersonByDocumentUseCase
import com.eflglobal.visitorsapp.domain.usecase.visit.CreateVisitUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

/**
 * ViewModel para el flujo de nueva visita (escaneo de documento + datos personales).
 */
class NewVisitViewModel(
    private val createPersonUseCase: CreatePersonUseCase,
    private val getPersonByDocumentUseCase: GetPersonByDocumentUseCase,
    private val createVisitUseCase: CreateVisitUseCase,
    private val createVisitUseCase: CreateVisitUseCase
    val uiState: StateFlow<NewVisitUiState> = _uiState.asStateFlow()

    // ── Transient flow data ────────────────────────────────────────────────────
    private var personId: String? = null
    private var documentType: String = ""

    /** "Yo soy un:" — who the visitor IS (VISITOR, CONTRACTOR, VENDOR, DELIVERY…) */
    private var visitorType: String = VisitReasonKeys.VISITOR

    /** "Motivo de visita" — WHY they are visiting (from PersonDataScreen) */
    private var visitReason: String = VisitReasonKeys.VISITOR

    /** Free-text description — only used when visitReason == "OTHER". */
    private var visitReasonCustom: String? = null

    private var documentFrontPath: String? = null
    private var documentBackPath: String? = null

    /** First name detected by OCR (from document front). */
    private var detectedFirstName: String? = null

    /** Last name detected by OCR (from document front). */
    private var detectedLastName: String? = null

    /** Document number detected by OCR — may be null. */
    private var documentNumber: String? = null

    /** Source layer that produced the name/docNumber (MRZ, OCR_KEYED, HEURISTIC, NONE). */
    private var extractionSource: DocumentDataExtractor.ExtractionSource =
        DocumentDataExtractor.ExtractionSource.NONE

    /** Confidence level of the extraction. */
    private var extractionConfidence: DocumentDataExtractor.Confidence =
        DocumentDataExtractor.Confidence.NONE

    // ── Public accessors ──────────────────────────────────────────────────────

    fun getPersonId(): String {
        if (personId == null) personId = java.util.UUID.randomUUID().toString()
        return personId!!
    }

    fun setDocumentType(type: String) { documentType = type }

    /** Sets "Yo soy un:" — who the visitor IS. Called from DocumentScanScreen. */
    fun setVisitorType(type: String) { visitorType = type }

    /**
     * Sets the visit reason — WHY they are visiting.
     * Called from PersonDataScreen.
     */
    fun setVisitReason(key: String, custom: String? = null) {
        visitReason       = key
        visitReasonCustom = if (key == VisitReasonKeys.OTHER) custom else null
    }

    /**
     * Called after front document is scanned.
     *
     * [firstName] and [lastName] come from DocumentDataExtractor (MRZ → OCR keyed → heuristic).
     * Both may be null when extraction failed — the form will show empty fields for manual entry.
     * We never invent a placeholder name here.
     */
    fun setDocumentFront(
        path: String,
        firstName: String? = null,
        lastName: String? = null,
        docNumber: String? = null,
        source: DocumentDataExtractor.ExtractionSource = DocumentDataExtractor.ExtractionSource.NONE,
        confidence: DocumentDataExtractor.Confidence   = DocumentDataExtractor.Confidence.NONE
    ) {
        documentFrontPath    = path
        documentNumber       = docNumber?.ifBlank { null }
        detectedFirstName    = firstName?.ifBlank { null }
        detectedLastName     = lastName?.ifBlank { null }
        extractionSource     = source
        extractionConfidence = confidence
    }

    fun setDocumentBack(path: String) { documentBackPath = path }

    fun getDetectedFirstName(): String? = detectedFirstName
    fun getDetectedLastName(): String?  = detectedLastName
    /** Convenience — joined for backward-compat display. */
    fun getDetectedName(): String? =
        listOfNotNull(detectedFirstName, detectedLastName)
            .joinToString(" ")
            .ifBlank { null }

    fun getDocumentNumber(): String?                               = documentNumber
    fun getExtractionSource(): DocumentDataExtractor.ExtractionSource = extractionSource
    fun getExtractionConfidence(): DocumentDataExtractor.Confidence   = extractionConfidence

    // ── Business logic ────────────────────────────────────────────────────────

    fun createPersonAndVisit(
        firstName: String,
        lastName: String,
        email: String,
        phoneNumber: String,
        company: String?,
        visitingPersonName: String,
        profilePhotoPath: String?
    ) {
        if (firstName.isBlank() || email.isBlank() || phoneNumber.isBlank() || visitingPersonName.isBlank()) {
            _uiState.value = NewVisitUiState.Error("All required fields must be filled")
            return
        }
        if (visitReason == VisitReasonKeys.OTHER && visitReasonCustom.isNullOrBlank()) {
            _uiState.value = NewVisitUiState.Error(
                "Please describe the reason for your visit"
            )
            return
        }

        _uiState.value = NewVisitUiState.Loading

        viewModelScope.launch {
            try {
                // Look up existing person by document number (if available)
                val existingPerson = documentNumber?.let { getPersonByDocumentUseCase(it) }

                val resolvedPersonId = if (existingPerson != null) {
                    // Person already exists — update their photos/data with the new visit's info
                    personRepository.updatePerson(
                        lastName          = lastName,
                        documentNumber    = documentNumber,
                        documentType      = documentType,
                        email             = email,
                        phoneNumber       = phoneNumber,
                        company           = company,
                        profilePhotoPath  = profilePhotoPath,
                        documentFrontPath = documentFrontPath,
                        documentBackPath  = documentBackPath
                    ).fold(
                        onSuccess = { it.personId },
                        onFailure = { error ->
                            _uiState.value = NewVisitUiState.Error(error.message ?: "Failed to create person")
                            return@launch
                        }
                    )
                }

                createVisitUseCase(
                    personId           = resolvedPersonId,
                    visitingPersonName = visitingPersonName,
                    visitorType        = visitorType,
                    visitReason        = visitReason,
                    visitReasonCustom  = visitReasonCustom
                ).fold(
                    onSuccess = { visit ->
                        _uiState.value = NewVisitUiState.Success(
                            qrCode           = visit.qrCodeValue,
                            personName       = "$firstName $lastName".trim(),
                            visitingPerson   = visitingPersonName,
                            company          = company,
                            profilePhotoPath = profilePhotoPath,
                            visitorType      = visitorType
                        )
                    },
                    onFailure = { error ->
                        _uiState.value = NewVisitUiState.Error(error.message ?: "Failed to create visit")
                    }
                )
            } catch (e: Exception) {
                _uiState.value = NewVisitUiState.Error(e.message ?: "An unexpected error occurred")
            }
        }
    }

    fun resetState() {
        _uiState.value       = NewVisitUiState.Idle
        documentType         = ""
        visitorType          = VisitReasonKeys.VISITOR
        visitReason          = VisitReasonKeys.VISITOR
        visitReasonCustom    = null
        documentFrontPath    = null
        documentBackPath     = null
        detectedFirstName    = null
        detectedLastName     = null
        documentNumber       = null
        extractionSource     = DocumentDataExtractor.ExtractionSource.NONE
        extractionConfidence = DocumentDataExtractor.Confidence.NONE
        personId             = null
    }

    /**
     * Called when user taps "Edit" on ConfirmScreen.
     * Resets ONLY the UiState back to Idle so PersonDataScreen doesn't
     * immediately re-navigate forward — all scanned/entered data is preserved.
     */
    fun resetToEditing() {
        _uiState.value = NewVisitUiState.Idle
    }
}

sealed class NewVisitUiState {
    object Idle    : NewVisitUiState()
    object Loading : NewVisitUiState()
    data class Success(
        val qrCode: String,
        val personName: String,
        val visitingPerson: String,
        val company: String?,
        val profilePhotoPath: String? = null,
        val visitorType: String = "VISITOR"
    ) : NewVisitUiState()
    data class Error(val message: String) : NewVisitUiState()
}

package com.eflglobal.visitorsapp.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.eflglobal.visitorsapp.core.ocr.DocumentDataExtractor
import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys
import com.eflglobal.visitorsapp.domain.usecase.person.CreatePersonUseCase
import com.eflglobal.visitorsapp.domain.usecase.person.GetPersonByDocumentUseCase
import com.eflglobal.visitorsapp.domain.usecase.visit.CreateVisitUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

/**
 * ViewModel para el flujo de nueva visita (escaneo de documento + datos personales).
 */
class NewVisitViewModel(
    private val createPersonUseCase: CreatePersonUseCase,
    private val getPersonByDocumentUseCase: GetPersonByDocumentUseCase,
    private val createVisitUseCase: CreateVisitUseCase
) : ViewModel() {

    private val _uiState = MutableStateFlow<NewVisitUiState>(NewVisitUiState.Idle)
    val uiState: StateFlow<NewVisitUiState> = _uiState.asStateFlow()

    // ── Transient flow data ────────────────────────────────────────────────────
    private var personId: String? = null

    /**
     * Pre-generated visitId — generated on first call to getVisitId().
     * Photos are saved to visits/{visitId}/ for an immutable audit trail.
     */
    private var visitId: String? = null

    private var documentType: String = ""

    /** "Yo soy un:" — who the visitor IS (VISITOR, CONTRACTOR, VENDOR, DELIVERY…) */
    private var visitorType: String = VisitReasonKeys.VISITOR

    /** "Motivo de visita" — WHY they are visiting (from PersonDataScreen) */
    private var visitReason: String = VisitReasonKeys.VISITOR

    /** Free-text description — only used when visitReason == "OTHER". */
    private var visitReasonCustom: String? = null

    private var documentFrontPath: String? = null
    private var documentBackPath: String? = null

    /** First name detected by OCR (from document front). */
    private var detectedFirstName: String? = null

    /** Last name detected by OCR (from document front). */
    private var detectedLastName: String? = null

    /** Document number detected by OCR — may be null. */
    private var documentNumber: String? = null

    /** Source layer that produced the name/docNumber (MRZ, OCR_KEYED, HEURISTIC, NONE). */
    private var extractionSource: DocumentDataExtractor.ExtractionSource =
        DocumentDataExtractor.ExtractionSource.NONE

    /** Confidence level of the extraction. */
    private var extractionConfidence: DocumentDataExtractor.Confidence =
        DocumentDataExtractor.Confidence.NONE

    // ── Public accessors ──────────────────────────────────────────────────────

    fun getPersonId(): String {
        if (personId == null) personId = java.util.UUID.randomUUID().toString()
        return personId!!
    }

    /**
     * Returns the pre-generated visitId for this visit flow.
     * All photos should be saved to visits/{visitId}/ using this ID.
     */
    fun getVisitId(): String {
        if (visitId == null) visitId = java.util.UUID.randomUUID().toString()
        return visitId!!
    }

    fun setDocumentType(type: String) { documentType = type }

    /** Sets "Yo soy un:" — who the visitor IS. Called from DocumentScanScreen. */
    fun setVisitorType(type: String) { visitorType = type }

    fun setVisitReason(key: String, custom: String? = null) {
        visitReason       = key
        visitReasonCustom = if (key == VisitReasonKeys.OTHER) custom else null
    }

    fun setDocumentFront(
        path: String,
        firstName: String? = null,
        lastName: String? = null,
        docNumber: String? = null,
        source: DocumentDataExtractor.ExtractionSource = DocumentDataExtractor.ExtractionSource.NONE,
        confidence: DocumentDataExtractor.Confidence   = DocumentDataExtractor.Confidence.NONE
    ) {
        documentFrontPath    = path
        documentNumber       = docNumber?.ifBlank { null }
        detectedFirstName    = firstName?.ifBlank { null }
        detectedLastName     = lastName?.ifBlank { null }
        extractionSource     = source
        extractionConfidence = confidence
    }

    fun setDocumentBack(path: String) { documentBackPath = path }

    fun getDetectedFirstName(): String? = detectedFirstName
    fun getDetectedLastName(): String?  = detectedLastName
    /** Convenience — joined for backward-compat display. */
    fun getDetectedName(): String? =
        listOfNotNull(detectedFirstName, detectedLastName)
            .joinToString(" ")
            .ifBlank { null }

    fun getDocumentNumber(): String?                               = documentNumber
    fun getExtractionSource(): DocumentDataExtractor.ExtractionSource = extractionSource
    fun getExtractionConfidence(): DocumentDataExtractor.Confidence   = extractionConfidence

    // ── Business logic ────────────────────────────────────────────────────────

    fun createPersonAndVisit(
        firstName: String,
        lastName: String,
        email: String,
        phoneNumber: String,
        company: String?,
        visitingPersonName: String,
        profilePhotoPath: String?
    ) {
        if (firstName.isBlank() || email.isBlank() || phoneNumber.isBlank() || visitingPersonName.isBlank()) {
            _uiState.value = NewVisitUiState.Error("All required fields must be filled")
            return
        }
        if (visitReason == VisitReasonKeys.OTHER && visitReasonCustom.isNullOrBlank()) {
            _uiState.value = NewVisitUiState.Error("Please describe the reason for your visit")
            return
        }

        _uiState.value = NewVisitUiState.Loading

        viewModelScope.launch {
            try {
                // Look up existing person by document number (if available).
                // If found: reuse their personId — do NOT update PersonEntity.
                // PersonEntity is an immutable identity record after first registration.
                val existingPerson = documentNumber?.let { getPersonByDocumentUseCase(it) }

                val resolvedPersonId = if (existingPerson != null) {
                    existingPerson.personId
                } else {
                    // Brand-new person — create identity record with today's photos
                    createPersonUseCase(
                        firstName         = firstName,
                        lastName          = lastName,
                        documentNumber    = documentNumber,
                        documentType      = documentType,
                        email             = email,
                        phoneNumber       = phoneNumber,
                        company           = company,
                        profilePhotoPath  = profilePhotoPath,
                        documentFrontPath = documentFrontPath,
                        documentBackPath  = documentBackPath
                    ).fold(
                        onSuccess = { it.personId },
                        onFailure = { error ->
                            _uiState.value = NewVisitUiState.Error(
                                error.message ?: "Failed to create person"
                            )
                            return@launch
                        }
                    )
                }

                // Always create a new visit with its own immutable photo snapshots
                createVisitUseCase(
                    personId               = resolvedPersonId,
                    visitingPersonName     = visitingPersonName,
                    visitorType            = visitorType,
                    visitReason            = visitReason,
                    visitReasonCustom      = visitReasonCustom,
                    visitId                = getVisitId(),
                    visitProfilePhotoPath  = profilePhotoPath,
                    visitDocumentFrontPath = documentFrontPath,
                    visitDocumentBackPath  = documentBackPath
                ).fold(
                    onSuccess = { visit ->
                        _uiState.value = NewVisitUiState.Success(
                            qrCode           = visit.qrCodeValue,
                            personName       = "$firstName $lastName".trim(),
                            visitingPerson   = visitingPersonName,
                            company          = company,
                            profilePhotoPath = profilePhotoPath,
                            visitorType      = visitorType
                        )
                    },
                    onFailure = { error ->
                        _uiState.value = NewVisitUiState.Error(
                            error.message ?: "Failed to create visit"
                        )
                    }
                )
            } catch (e: Exception) {
                _uiState.value = NewVisitUiState.Error(e.message ?: "An unexpected error occurred")
            }
        }
    }

    fun resetState() {
        _uiState.value       = NewVisitUiState.Idle
        documentType         = ""
        visitorType          = VisitReasonKeys.VISITOR
        visitReason          = VisitReasonKeys.VISITOR
        visitReasonCustom    = null
        documentFrontPath    = null
        documentBackPath     = null
        detectedFirstName    = null
        detectedLastName     = null
        documentNumber       = null
        extractionSource     = DocumentDataExtractor.ExtractionSource.NONE
        extractionConfidence = DocumentDataExtractor.Confidence.NONE
        personId             = null
        visitId              = null   // new visitId will be generated on next flow
    }

    /**
     * Called when user taps "Edit" on ConfirmScreen.
     * Resets ONLY the UiState back to Idle so PersonDataScreen doesn't
     * immediately re-navigate forward — all scanned/entered data is preserved.
     */
    fun resetToEditing() {
        _uiState.value = NewVisitUiState.Idle
    }
}

sealed class NewVisitUiState {
    object Idle    : NewVisitUiState()
    object Loading : NewVisitUiState()
    data class Success(
        val qrCode: String,
        val personName: String,
        val visitingPerson: String,
        val company: String?,
        val profilePhotoPath: String? = null,
        val visitorType: String = "VISITOR"
    ) : NewVisitUiState()
    data class Error(val message: String) : NewVisitUiState()
}

package com.eflglobal.visitorsapp.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.eflglobal.visitorsapp.core.ocr.DocumentDataExtractor
import com.eflglobal.visitorsapp.domain.model.Person
import com.eflglobal.visitorsapp.domain.model.Visit
import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys
import com.eflglobal.visitorsapp.domain.repository.PersonRepository
import com.eflglobal.visitorsapp.domain.repository.VisitRepository
import com.eflglobal.visitorsapp.domain.usecase.visit.CreateVisitUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

/**
 * ViewModel para crear visita recurrente (visitante ya registrado).
 */
class RecurrentVisitViewModel(
    private val createVisitUseCase: CreateVisitUseCase,
    private val personRepository: PersonRepository,
    private val visitRepository: VisitRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<RecurrentVisitUiState>(RecurrentVisitUiState.Idle)
    val uiState: StateFlow<RecurrentVisitUiState> = _uiState.asStateFlow()

    /** Emits the last visit once it is loaded — screen observes to pre-fill fields. */
    private val _lastVisitPreFill = MutableStateFlow<Visit?>(null)
    val lastVisitPreFill: StateFlow<Visit?> = _lastVisitPreFill.asStateFlow()

    private var selectedPerson: Person? = null

    /** Last visit data for this person — pre-fills form fields. */
    private var lastVisit: Visit? = null

    var documentType: String = "DUI"; private set

    private var visitorType: String = VisitReasonKeys.VISITOR
    private var visitReason: String = VisitReasonKeys.VISITOR
    private var visitReasonCustom: String? = null

    // Document scan paths — mirrors NewVisitViewModel
    var documentFrontPath: String? = null; private set
    var documentBackPath:  String? = null; private set

    // Profile photo taken on this visit (may differ from person.profilePhotoPath)
    var profilePhotoPath: String? = null; private set

    // ── Draft editable fields — survive popBackStack() for "Edit" flow ────────
    var draftFirstName:    String? = null; private set
    var draftLastName:     String? = null; private set
    var draftDoc:          String? = null; private set
    var draftCompany:      String? = null; private set
    var draftEmail:        String? = null; private set
    var draftPhone:        String? = null; private set
    var draftVisitingPerson: String? = null; private set
    var draftVisitReasonKey: String? = null; private set
    var draftVisitReasonCustom: String? = null; private set
    /** True once the user has submitted once — screen should restore drafts. */
    var hasDraft: Boolean = false; private set

    fun saveDraft(
        firstName: String, lastName: String, doc: String, company: String,
        email: String, phone: String, visitingPerson: String,
        visitReasonKey: String?, visitReasonCustom: String?
    ) {
        draftFirstName       = firstName
        draftLastName        = lastName
        draftDoc             = doc
        draftCompany         = company
        draftEmail           = email
        draftPhone           = phone
        draftVisitingPerson  = visitingPerson
        draftVisitReasonKey  = visitReasonKey
        draftVisitReasonCustom = visitReasonCustom
        hasDraft             = true
    }

    fun setSelectedPerson(person: Person) {
        selectedPerson = person
        _lastVisitPreFill.value = null  // reset while loading
        // Load last visit to pre-fill form fields
        viewModelScope.launch {
            val last = visitRepository.getLastVisitByPersonId(person.personId)
            lastVisit = last
            if (last != null) {
                // Pre-fill visitor type and visit reason from most recent visit
                visitorType         = last.visitorType
                visitReason         = last.visitReason
                visitReasonCustom   = last.visitReasonCustom
                draftVisitingPerson = last.visitingPersonName
                _lastVisitPreFill.value = last
            }
        }
    }

    fun setDocumentType(type: String)     { documentType = type }
    fun setVisitorType(type: String)      { visitorType = type }
    fun setDocumentFront(path: String)    { documentFrontPath = path }
    fun setDocumentBack(path: String)     { documentBackPath  = path }
    fun setProfilePhoto(path: String)     { profilePhotoPath  = path }

    fun setVisitReason(key: String, custom: String? = null) {
        visitReason       = key
        visitReasonCustom = if (key == VisitReasonKeys.OTHER) custom else null
    }

    fun getSelectedPerson(): Person? = selectedPerson
    fun getLastVisit(): Visit? = lastVisit

    fun createVisit(
        visitingPersonName: String,
        editedFirstName: String? = null,
        editedLastName: String? = null,
        editedCompany: String? = null,
        editedEmail: String? = null,
        editedPhone: String? = null
    ) {
        val person = selectedPerson
        if (person == null) {
            _uiState.value = RecurrentVisitUiState.Error("No person selected"); return
        }
        if (visitingPersonName.isBlank()) {
            _uiState.value = RecurrentVisitUiState.Error("Visiting person name is required"); return
        }
        if (visitReason == VisitReasonKeys.OTHER && visitReasonCustom.isNullOrBlank()) {
            _uiState.value = RecurrentVisitUiState.Error("Please describe the reason for the visit"); return
        }

        val finalFirstName = (editedFirstName?.trim()?.ifBlank { null } ?: person.firstName).trim()
        val finalLastName = (editedLastName?.trim()?.ifBlank { null } ?: person.lastName).trim()
        val finalCompany = editedCompany?.trim()?.ifBlank { null } ?: person.company
        val finalEmail = (editedEmail?.trim()?.ifBlank { null } ?: person.email).trim()
        val finalPhone = (editedPhone?.trim()?.ifBlank { null } ?: person.phoneNumber).trim()

        val displayName = buildString {
            append(finalFirstName)
            if (finalLastName.isNotBlank()) { append(" "); append(finalLastName) }
        }.trim().ifBlank { person.fullName }

        _uiState.value = RecurrentVisitUiState.Loading

        viewModelScope.launch {
            try {
                // First, update person record with any edited data
                val newPhoto = profilePhotoPath
                val hasChanges =
                    finalFirstName != person.firstName ||
                    finalLastName  != person.lastName  ||
                    finalCompany   != person.company   ||
                    finalLastName != person.lastName ||
                    finalCompany != person.company ||
                    finalEmail != person.email ||
                    finalPhone != person.phoneNumber ||
                    (newPhoto != null && newPhoto != person.profilePhotoPath)
                        person.copy(
                            firstName         = finalFirstName,
                            lastName          = finalLastName,
                            company           = finalCompany,
                            email             = finalEmail,
                            phoneNumber       = finalPhone,
                            firstName = finalFirstName,
                            lastName = finalLastName,
                            company = finalCompany,
                            email = finalEmail,
                            phoneNumber = finalPhone,
                            profilePhotoPath = newPhoto ?: person.profilePhotoPath
                    visitorType        = visitorType,
                    visitReason        = visitReason,
                    visitReasonCustom  = visitReasonCustom
                )
                result.fold(
                    onSuccess = { visit ->
                        _uiState.value = RecurrentVisitUiState.Success(
                            qrCode           = visit.qrCodeValue,
                            personName       = displayName,
                            visitingPerson   = visitingPersonName,
                            company          = finalCompany,
                            profilePhotoPath = newPhoto ?: person.profilePhotoPath,
                            visitorType      = visitorType
                        )
                    },
                    onFailure = { error ->
                        _uiState.value = RecurrentVisitUiState.Error(error.message ?: "Failed to create visit")
                    }
                )
            } catch (e: Exception) {
                _uiState.value = RecurrentVisitUiState.Error(e.message ?: "An unexpected error occurred")
            }
        }
    }

    fun resetState() {
        _uiState.value          = RecurrentVisitUiState.Idle
        _lastVisitPreFill.value = null
        selectedPerson          = null
        lastVisit               = null
        documentType            = "DUI"
        visitorType          = VisitReasonKeys.VISITOR
        visitReason          = VisitReasonKeys.VISITOR
        visitReasonCustom    = null
        documentFrontPath    = null
        documentBackPath     = null
        profilePhotoPath     = null
        draftFirstName       = null
        draftLastName        = null
        draftDoc             = null
        draftCompany         = null
        draftEmail           = null
        draftPhone           = null
        draftVisitingPerson  = null
        draftVisitReasonKey  = null
        draftVisitReasonCustom = null
        hasDraft             = false
    }

    /** Resets only UiState to Idle — preserves all captured data for editing. */
    fun resetToEditing() { _uiState.value = RecurrentVisitUiState.Idle }

    /**
     * Resets document scan + photo state only.
     * Called when the user goes back from RecurrentDocumentScanScreen so that
     * re-entering the screen starts fresh (no stale "already scanned" state).
     */
    fun resetDocuments() {
        documentFrontPath = null
        documentBackPath  = null
        profilePhotoPath  = null
        documentType      = "DUI"
        visitorType       = VisitReasonKeys.VISITOR
    }
}

sealed class RecurrentVisitUiState {
    object Idle    : RecurrentVisitUiState()
    object Loading : RecurrentVisitUiState()
    data class Success(
        val qrCode: String,
        val personName: String,
        val visitingPerson: String,
        val company: String?,
        val profilePhotoPath: String? = null,
        val visitorType: String = "VISITOR"
    ) : RecurrentVisitUiState()
    data class Error(val message: String) : RecurrentVisitUiState()
}

package com.eflglobal.visitorsapp.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.eflglobal.visitorsapp.domain.model.Person
import com.eflglobal.visitorsapp.domain.model.Visit
import com.eflglobal.visitorsapp.domain.model.VisitReasonKeys
import com.eflglobal.visitorsapp.domain.repository.PersonRepository
import com.eflglobal.visitorsapp.domain.repository.VisitRepository
import com.eflglobal.visitorsapp.domain.usecase.visit.CreateVisitUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

/**
 * ViewModel para crear visita recurrente (visitante ya registrado).
 */
class RecurrentVisitViewModel(
    private val createVisitUseCase: CreateVisitUseCase,
    private val personRepository: PersonRepository,
    private val visitRepository: VisitRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<RecurrentVisitUiState>(RecurrentVisitUiState.Idle)
    val uiState: StateFlow<RecurrentVisitUiState> = _uiState.asStateFlow()

    /** Emits the last visit once it is loaded — screen observes to pre-fill fields. */
    private val _lastVisitPreFill = MutableStateFlow<Visit?>(null)
    val lastVisitPreFill: StateFlow<Visit?> = _lastVisitPreFill.asStateFlow()

    private var selectedPerson: Person? = null

    /** Last visit data for this person — pre-fills form fields. */
    private var lastVisit: Visit? = null

    var documentType: String = "DUI"; private set

    private var visitorType: String = VisitReasonKeys.VISITOR
    private var visitReason: String = VisitReasonKeys.VISITOR
    private var visitReasonCustom: String? = null

    // Document scan paths — mirrors NewVisitViewModel
    var documentFrontPath: String? = null; private set
    var documentBackPath:  String? = null; private set

    // Profile photo taken on this visit (may differ from person.profilePhotoPath)
    var profilePhotoPath: String? = null; private set

    /**
     * Pre-generated visitId for this recurring visit flow.
     * Photos are saved to visits/{visitId}/ for an immutable audit trail.
     */
    private var visitId: String? = null

    // ── Draft editable fields — survive popBackStack() for "Edit" flow ────────
    var draftFirstName:    String? = null; private set
    var draftLastName:     String? = null; private set
    var draftDoc:          String? = null; private set
    var draftCompany:      String? = null; private set
    var draftEmail:        String? = null; private set
    var draftPhone:        String? = null; private set
    var draftVisitingPerson: String? = null; private set
    var draftVisitReasonKey: String? = null; private set
    var draftVisitReasonCustom: String? = null; private set
    /** True once the user has submitted once — screen should restore drafts. */
    var hasDraft: Boolean = false; private set

    fun saveDraft(
        firstName: String, lastName: String, doc: String, company: String,
        email: String, phone: String, visitingPerson: String,
        visitReasonKey: String?, visitReasonCustom: String?
    ) {
        draftFirstName       = firstName
        draftLastName        = lastName
        draftDoc             = doc
        draftCompany         = company
        draftEmail           = email
        draftPhone           = phone
        draftVisitingPerson  = visitingPerson
        draftVisitReasonKey  = visitReasonKey
        draftVisitReasonCustom = visitReasonCustom
        hasDraft             = true
    }

    fun setSelectedPerson(person: Person) {
        selectedPerson = person
        _lastVisitPreFill.value = null  // reset while loading
        // Load last visit to pre-fill form fields
        viewModelScope.launch {
            val last = visitRepository.getLastVisitByPersonId(person.personId)
            lastVisit = last
            if (last != null) {
                // Pre-fill visitor type and visit reason from most recent visit
                visitorType         = last.visitorType
                visitReason         = last.visitReason
                visitReasonCustom   = last.visitReasonCustom
                draftVisitingPerson = last.visitingPersonName
                _lastVisitPreFill.value = last
            }
        }
    }

    fun setDocumentType(type: String)     { documentType = type }
    fun setVisitorType(type: String)      { visitorType = type }
    fun setDocumentFront(path: String)    { documentFrontPath = path }
    fun setDocumentBack(path: String)     { documentBackPath  = path }
    fun setProfilePhoto(path: String)     { profilePhotoPath  = path }

    /**
     * Returns the pre-generated visitId for this recurring visit flow.
     * All photos should be saved to visits/{visitId}/ using this ID.
     */
    fun getVisitId(): String {
        if (visitId == null) visitId = java.util.UUID.randomUUID().toString()
        return visitId!!
    }

    fun setVisitReason(key: String, custom: String? = null) {
        visitReason       = key
        visitReasonCustom = if (key == VisitReasonKeys.OTHER) custom else null
    }

    fun getSelectedPerson(): Person? = selectedPerson
    fun getLastVisit(): Visit? = lastVisit

    fun createVisit(
        visitingPersonName: String,
        editedFirstName: String? = null,
        editedLastName: String? = null,
        editedCompany: String? = null,
        editedEmail: String? = null,
        editedPhone: String? = null
    ) {
        val person = selectedPerson
        if (person == null) {
            _uiState.value = RecurrentVisitUiState.Error("No person selected"); return
        }
        if (visitingPersonName.isBlank()) {
            _uiState.value = RecurrentVisitUiState.Error("Visiting person name is required"); return
        }
        if (visitReason == VisitReasonKeys.OTHER && visitReasonCustom.isNullOrBlank()) {
            _uiState.value = RecurrentVisitUiState.Error("Please describe the reason for the visit"); return
        }

        val finalFirstName = (editedFirstName?.trim()?.ifBlank { null } ?: person.firstName).trim()
        val finalLastName = (editedLastName?.trim()?.ifBlank { null } ?: person.lastName).trim()
        val finalCompany = editedCompany?.trim()?.ifBlank { null } ?: person.company
        val finalEmail = (editedEmail?.trim()?.ifBlank { null } ?: person.email).trim()
        val finalPhone = (editedPhone?.trim()?.ifBlank { null } ?: person.phoneNumber).trim()

        val displayName = buildString {
            append(finalFirstName)
            if (finalLastName.isNotBlank()) { append(" "); append(finalLastName) }
        }.trim().ifBlank { person.fullName }

        _uiState.value = RecurrentVisitUiState.Loading

        viewModelScope.launch {
            try {
                val newPhoto  = profilePhotoPath
                val newFront  = documentFrontPath?.ifBlank { null }
                val newBack   = documentBackPath?.ifBlank  { null }

                // Update PersonEntity only for personal data changes (name, contact, company).
                // Profile photo in PersonEntity is updated so list views show the current face.
                // Document photos are NOT updated — they belong to VisitEntity as audit snapshots.
                val hasPersonChanges =
                    finalFirstName != person.firstName ||
                    finalLastName  != person.lastName  ||
                    finalCompany   != person.company   ||
                    finalEmail     != person.email     ||
                    finalPhone     != person.phoneNumber ||
                    (newPhoto != null && newPhoto != person.profilePhotoPath)

                if (hasPersonChanges) {
                    personRepository.updatePerson(
                        person.copy(
                            firstName        = finalFirstName,
                            lastName         = finalLastName,
                            company          = finalCompany,
                            email            = finalEmail,
                            phoneNumber      = finalPhone,
                            profilePhotoPath = newPhoto ?: person.profilePhotoPath
                            // documentFrontPath / documentBackPath intentionally NOT updated:
                            // visit-specific docs go into VisitEntity.visitDocumentFrontPath/Back
                        )
                    )
                }

                // Create the new visit with its own immutable photo snapshots
                val result = createVisitUseCase(
                    personId               = person.personId,
                    visitingPersonName     = visitingPersonName,
                    visitorType            = visitorType,
                    visitReason            = visitReason,
                    visitReasonCustom      = visitReasonCustom,
                    visitId                = getVisitId(),
                    visitProfilePhotoPath  = newPhoto,
                    visitDocumentFrontPath = newFront,
                    visitDocumentBackPath  = newBack
                )
                result.fold(
                    onSuccess = { visit ->
                        _uiState.value = RecurrentVisitUiState.Success(
                            qrCode           = visit.qrCodeValue,
                            personName       = displayName,
                            visitingPerson   = visitingPersonName,
                            company          = finalCompany,
                            profilePhotoPath = newPhoto ?: person.profilePhotoPath,
                            visitorType      = visitorType
                        )
                    },
                    onFailure = { error ->
                        _uiState.value = RecurrentVisitUiState.Error(error.message ?: "Failed to create visit")
                    }
                )
            } catch (e: Exception) {
                _uiState.value = RecurrentVisitUiState.Error(e.message ?: "An unexpected error occurred")
            }
        }
    }

    fun resetState() {
        _uiState.value          = RecurrentVisitUiState.Idle
        _lastVisitPreFill.value = null
        selectedPerson          = null
        lastVisit               = null
        documentType            = "DUI"
        visitorType          = VisitReasonKeys.VISITOR
        visitReason          = VisitReasonKeys.VISITOR
        visitReasonCustom    = null
        documentFrontPath    = null
        documentBackPath     = null
        profilePhotoPath     = null
        visitId              = null
        draftFirstName       = null
        draftLastName        = null
        draftDoc             = null
        draftCompany         = null
        draftEmail           = null
        draftPhone           = null
        draftVisitingPerson  = null
        draftVisitReasonKey  = null
        draftVisitReasonCustom = null
        hasDraft             = false
    }

    /** Resets only UiState to Idle — preserves all captured data for editing. */
    fun resetToEditing() { _uiState.value = RecurrentVisitUiState.Idle }

    /**
     * Resets document scan + photo state only.
     * Called when the user goes back from RecurrentDocumentScanScreen.
     * Also resets visitId so photos are saved under a fresh visitId on retry.
     */
    fun resetDocuments() {
        documentFrontPath = null
        documentBackPath  = null
        profilePhotoPath  = null
        documentType      = "DUI"
        visitorType       = VisitReasonKeys.VISITOR
        visitId           = null  // fresh visitId for next scan attempt
    }
}

sealed class RecurrentVisitUiState {
    object Idle    : RecurrentVisitUiState()
    object Loading : RecurrentVisitUiState()
    data class Success(
        val qrCode: String,
        val personName: String,
        val visitingPerson: String,
        val company: String?,
        val profilePhotoPath: String? = null,
        val visitorType: String = "VISITOR"
    ) : RecurrentVisitUiState()
    data class Error(val message: String) : RecurrentVisitUiState()
}

package com.eflglobal.visitorsapp.ui.viewmodel

import android.content.Context
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import com.eflglobal.visitorsapp.core.DependencyProvider
import com.eflglobal.visitorsapp.domain.usecase.person.CreatePersonUseCase
import com.eflglobal.visitorsapp.domain.usecase.person.GetPersonByDocumentUseCase
import com.eflglobal.visitorsapp.domain.usecase.person.SearchPersonsUseCase
import com.eflglobal.visitorsapp.domain.usecase.station.CreateStationUseCase
import com.eflglobal.visitorsapp.domain.usecase.station.HasActiveStationUseCase
import com.eflglobal.visitorsapp.domain.usecase.visit.CreateVisitUseCase
import com.eflglobal.visitorsapp.domain.usecase.visit.EndVisitByQRUseCase
import com.eflglobal.visitorsapp.domain.usecase.visit.SearchActiveVisitsUseCase

/**
 * Factory para crear ViewModels con sus dependencias.
 */
class ViewModelFactory(private val context: Context) : ViewModelProvider.Factory {

    @Suppress("UNCHECKED_CAST")
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        // Obtener repositorios
        val personRepository = DependencyProvider.providePersonRepository(context)
        val visitRepository = DependencyProvider.provideVisitRepository(context)
        val stationRepository = DependencyProvider.provideStationRepository(context)

        return when {
            modelClass.isAssignableFrom(StationSetupViewModel::class.java) -> {
                StationSetupViewModel(
                    hasActiveStationUseCase = HasActiveStationUseCase(stationRepository),
                    createStationUseCase = CreateStationUseCase(stationRepository)
                ) as T
            }

            modelClass.isAssignableFrom(NewVisitViewModel::class.java) -> {
                NewVisitViewModel(
                    createPersonUseCase = CreatePersonUseCase(personRepository),
                    getPersonByDocumentUseCase = GetPersonByDocumentUseCase(personRepository),
                    createVisitUseCase = CreateVisitUseCase(visitRepository, stationRepository)
                ) as T
            }

            modelClass.isAssignableFrom(RecurrentSearchViewModel::class.java) -> {
                RecurrentSearchViewModel(
                    searchPersonsUseCase = SearchPersonsUseCase(personRepository)
                ) as T
            }

            modelClass.isAssignableFrom(RecurrentVisitViewModel::class.java) -> {
                RecurrentVisitViewModel(
                    createVisitUseCase = CreateVisitUseCase(visitRepository, stationRepository),
                    personRepository   = personRepository,
                    visitRepository    = visitRepository
                ) as T
            }

            modelClass.isAssignableFrom(EndVisitViewModel::class.java) -> {
                EndVisitViewModel(
                    endVisitByQRUseCase = EndVisitByQRUseCase(visitRepository),
                    searchActiveVisitsUseCase = SearchActiveVisitsUseCase(visitRepository),
                    personRepository = personRepository
                ) as T
            }

            modelClass.isAssignableFrom(AdminPanelViewModel::class.java) -> {
                AdminPanelViewModel(
                    stationRepository = stationRepository,
                    visitRepository = visitRepository
                ) as T
            }

            else -> throw IllegalArgumentException("Unknown ViewModel class: ${modelClass.name}")
        }
    }
}

